export type SeedQuestion = {
  title: string;
  prompt: string;
  type: string;
  difficulty: string;
  topic: number;
  answer: string;
  companies?: number[];
  roleTags?: string[];
  areaTags?: string[];
  patternTags?: string[];
  // MOM-045: DSA items link out to the source problem rather than embedding its
  // statement (D-008 / ADR-0004). sourceUrl is optional because non-DSA items
  // (backend/CS-fundamentals questions) are original prompts with no external source.
  sourceUrl?: string;
};

export const questions: SeedQuestion[] = [
  { title: 'Design an idempotent payment endpoint', prompt: 'How would you design a POST payment endpoint so client retries cannot charge a customer twice?', type: 'backend', difficulty: 'hard', topic: 0, answer: 'Require a client-generated idempotency key, persist it with the request fingerprint and outcome in the same transaction as the payment state, return the stored result for matching retries, and reject reuse with a different payload. Define key expiry and handle concurrent inserts with a unique constraint.', companies: [1, 4] },
  { title: 'REST pagination tradeoffs', prompt: 'Compare offset pagination and cursor pagination. When would you choose each?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Offset pagination is simple and supports page jumps but becomes slow at large offsets and can duplicate or skip records during writes. Cursor pagination uses a stable ordered key, scales better, and remains consistent under inserts, but does not naturally support arbitrary page jumps.' },
  { title: 'API rate limiter design', prompt: 'Explain how to implement a distributed rate limiter for a public API.', type: 'backend', difficulty: 'hard', topic: 0, answer: 'Choose a policy such as token bucket, identify the key and limit window, and perform atomic state changes in a shared store such as Redis using Lua. Return standard limit headers, account for clock and store failures, and define whether failures are open or closed.', companies: [0, 3] },
  { title: 'Reliable background jobs', prompt: 'What guarantees and failure modes should a background job system handle?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'Assume at-least-once delivery, make handlers idempotent, acknowledge only after success, retry transient failures with bounded exponential backoff and jitter, send poison jobs to a dead-letter queue, and expose queue age, retry, and failure metrics.' },

  { title: 'JavaScript event loop ordering', prompt: 'Given timers, resolved promises, and synchronous code, explain the execution order in Node.js.', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'Synchronous code runs first. After the current stack finishes, promise reactions run from the microtask queue before the event loop advances to timer callbacks. Node also has phase-specific queues and process.nextTick runs before ordinary promise microtasks.' },
  { title: 'Closures and retained state', prompt: 'What is a closure, and how can closures accidentally cause memory retention?', type: 'javascript', difficulty: 'easy', topic: 1, answer: 'A closure is a function together with references to its lexical environment. As long as the function remains reachable, captured objects remain reachable too; long-lived listeners, timers, or caches can therefore retain large object graphs.' },
  { title: 'TypeScript unknown versus any', prompt: 'Why is unknown safer than any at an external data boundary?', type: 'typescript', difficulty: 'easy', topic: 1, answer: 'Any disables type checking and permits arbitrary operations. Unknown requires narrowing or validation before use, so untrusted JSON cannot silently flow into code that assumes a specific shape.' },
  { title: 'Model a state machine with TypeScript', prompt: 'How would you use discriminated unions to prevent invalid UI or workflow states?', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'Represent each valid state as an object with a shared literal discriminator and only the fields valid in that state. Exhaustively switch on the discriminator and use never checking so new states require explicit handling.' },

  { title: 'How a composite index is used', prompt: 'For an index on (user_id, created_at), which queries benefit and why?', type: 'database', difficulty: 'medium', topic: 2, answer: 'The index efficiently supports predicates beginning with user_id and can provide created_at ordering within a user. It generally cannot efficiently satisfy a predicate on created_at alone because of the leftmost-prefix rule.' },
  { title: 'Transaction isolation anomalies', prompt: 'Describe dirty reads, non-repeatable reads, and phantom reads, then relate them to isolation levels.', type: 'database', difficulty: 'hard', topic: 2, answer: 'A dirty read observes uncommitted data, a non-repeatable read sees a row change between reads, and a phantom is a changed result set for a repeated predicate. Stronger isolation levels prevent progressively more anomalies; serializable aims to match some serial execution but may require retries.' },
  { title: 'Diagnose a slow SQL query', prompt: 'Walk through a disciplined process for diagnosing and improving a slow query.', type: 'database', difficulty: 'medium', topic: 2, answer: 'Capture the exact query and parameters, inspect EXPLAIN ANALYZE, compare estimated and actual rows, identify scans, joins, sorts, and lock waits, then improve indexing, statistics, query shape, or schema. Re-measure with representative data and workload.' },
  { title: 'Optimistic versus pessimistic locking', prompt: 'Compare optimistic and pessimistic concurrency control with practical use cases.', type: 'database', difficulty: 'medium', topic: 2, answer: 'Optimistic locking detects conflicts at write time using a version and works well when contention is low. Pessimistic locking acquires database locks before mutation and suits short, high-contention critical sections, but increases blocking and deadlock risk.' },

  { title: 'Process versus thread', prompt: 'Compare processes and threads in terms of isolation, communication, and failure behavior.', type: 'os', difficulty: 'easy', topic: 3, answer: 'Processes have separate virtual address spaces and stronger isolation; communication requires IPC. Threads share process memory and resources, making communication cheap but synchronization necessary and memory corruption capable of affecting the whole process.' },
  { title: 'Virtual memory and page faults', prompt: 'Explain virtual memory and what happens during a page fault.', type: 'os', difficulty: 'medium', topic: 3, answer: 'Virtual memory maps per-process virtual addresses to physical frames through page tables. On a missing mapping, the CPU traps into the kernel; the kernel validates access, loads or allocates the page if valid, updates the page table, and resumes, or terminates the process for invalid access.' },
  { title: 'Deadlock conditions and prevention', prompt: 'What four conditions are required for deadlock, and how can a system prevent it?', type: 'os', difficulty: 'medium', topic: 3, answer: 'Mutual exclusion, hold-and-wait, no preemption, and circular wait must all hold. Break one condition through ordered lock acquisition, acquiring resources together, timeouts or preemption where possible, or avoiding exclusive resources.' },
  { title: 'Mutex versus semaphore', prompt: 'When should you use a mutex, a counting semaphore, or a condition variable?', type: 'os', difficulty: 'medium', topic: 3, answer: 'A mutex protects exclusive access and has ownership. A counting semaphore represents a number of available permits or signals events. A condition variable lets threads sleep until a predicate over protected state may have changed and must be paired with a mutex and predicate loop.' },

  { title: 'TCP connection establishment', prompt: 'Explain the TCP three-way handshake and why two messages are insufficient.', type: 'networking', difficulty: 'easy', topic: 4, answer: 'The client sends SYN with its initial sequence number, the server replies SYN-ACK with its own number and acknowledgment, and the client ACKs it. The final acknowledgment confirms bidirectional reachability and that both initial sequence numbers were received.' },
  { title: 'What happens after entering a URL', prompt: 'Trace the major steps from entering an HTTPS URL to receiving the response.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'The browser resolves DNS, establishes a transport connection, performs TLS negotiation and certificate validation, sends an HTTP request, and receives and parses the response. Caches, proxies, CDN routing, connection reuse, and HTTP/2 or HTTP/3 may alter individual steps.' },
  { title: 'HTTP caching semantics', prompt: 'Explain Cache-Control, ETag, and conditional requests.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Cache-Control defines freshness and storage policy. ETag identifies a representation version. Once stale, a cache can send If-None-Match; the origin returns 304 if unchanged, avoiding transfer of the full body.' },
  { title: 'TCP versus UDP', prompt: 'Compare TCP and UDP and give applications that fit each.', type: 'networking', difficulty: 'easy', topic: 4, answer: 'TCP provides an ordered reliable byte stream with congestion control and connection state. UDP provides independent best-effort datagrams with lower protocol overhead. Web APIs commonly use TCP or QUIC-based HTTP; real-time media and DNS often value UDP behavior.' },

  { title: 'Composition over inheritance', prompt: 'Why is composition often preferred over deep inheritance hierarchies?', type: 'oop', difficulty: 'easy', topic: 5, answer: 'Composition assembles behavior through explicit collaborators, reducing coupling to a base-class implementation and allowing behavior to vary independently. Inheritance remains useful for genuine substitutability but deep hierarchies make changes and testing harder.' },
  { title: 'Apply the dependency inversion principle', prompt: 'Show how dependency inversion improves the testability of an order service.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'Make the order service depend on small interfaces for payment, persistence, and notifications, then inject implementations. Tests can provide deterministic fakes without network or database access, while production wiring supplies concrete adapters.' },
  { title: 'Liskov substitution in practice', prompt: 'Give an example of an inheritance design that violates Liskov substitution and explain the fix.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'A writable Rectangle API with Square as a subtype violates expectations when width and height setters cannot vary independently. Model immutable shapes with area behavior or separate interfaces instead of claiming an invalid behavioral subtype relationship.' },
  { title: 'Encapsulation beyond private fields', prompt: 'What does good encapsulation mean beyond marking fields private?', type: 'oop', difficulty: 'easy', topic: 5, answer: 'Good encapsulation protects invariants and exposes intention-revealing operations rather than raw state mutation. It keeps related data and behavior together, limits temporal coupling, and prevents callers from constructing invalid states.' },

  { title: 'Design a URL shortener', prompt: 'Design a production URL-shortening service, including APIs, storage, key generation, redirects, and scaling.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Define create and redirect APIs, estimate read-heavy capacity, generate collision-resistant short keys, store key-to-URL mappings in a partitionable database, cache hot redirects, and use CDN or edge routing. Address expiration, abuse, analytics, and availability tradeoffs.', companies: [0, 2] },
  { title: 'Design a notification platform', prompt: 'Design a service that sends email, SMS, and push notifications reliably.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Accept validated requests, persist intent, fan out through durable queues by channel, use provider adapters and idempotent workers, track per-recipient state, retry transient errors, dead-letter permanent failures, enforce preferences and rate limits, and monitor delivery latency.' },
  { title: 'Scale a read-heavy feed', prompt: 'Compare fan-out-on-write and fan-out-on-read for a social feed.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Fan-out-on-write precomputes followers feeds for fast reads but makes celebrity writes expensive. Fan-out-on-read assembles feeds at request time, reducing write amplification but increasing read latency. A hybrid commonly precomputes ordinary users and merges celebrity posts at read time.', companies: [3] },
  { title: 'Choose consistency for inventory', prompt: 'How would you prevent overselling inventory across concurrent orders?', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Keep authoritative inventory updates in a strongly consistent boundary using conditional writes, row locks, or a serialized partition. Represent reservations with expiration, make checkout idempotent, release timed-out reservations, and reconcile downstream events without treating caches as authoritative.' },

  // MOM-055: System Design cases batch 1 (toward the plan's 25-case Gate-3 target).
  // Each answer sketches the plan §7.4 seven-section shape (requirements,
  // estimation, API, data model, high-level design, deep dives, tradeoffs) at a
  // level appropriate for a reveal-answer reference outline, not a full essay.
  { title: 'Design a rate limiter service', prompt: 'Design a distributed rate limiter that multiple API gateway instances can share consistently.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: per-key limits (user/IP/API key), low added latency, consistent across instances. Estimation: peak requests/sec drives the shared store\'s throughput needs. API: checkAndIncrement(key, limit, window). Data model: a counter or sliding-window log per key in Redis, with TTL matching the window. High-level: gateway calls the shared store synchronously (or a local cache with periodic sync for lower latency, trading strict accuracy). Deep dive: token bucket vs. sliding-window-log accuracy/memory tradeoffs; Lua script for atomic check-and-increment. Tradeoffs: strict accuracy (shared store round trip per request) vs. approximate/local (faster, occasional over-limit bursts).' },
  { title: 'Design a distributed key-value store', prompt: 'Design a horizontally-scalable key-value store (like a simplified DynamoDB) with tunable consistency.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: high availability, horizontal scale, configurable consistency. Estimation: key space size and read/write ratio drive partition count. API: get(key), put(key, value), delete(key). Data model: consistent hashing to assign keys to nodes, with virtual nodes for even distribution. High-level: replicate each key to N nodes; use quorum reads/writes (R+W>N) for tunable consistency; vector clocks or last-write-wins for conflict resolution. Deep dive: handling node failure/rebalancing via consistent hashing\'s minimal-reshuffle property; read-repair and anti-entropy (Merkle trees) for eventual convergence. Tradeoffs: stronger quorums increase latency and reduce availability during partitions (CAP).' },
  { title: 'Design a chat application', prompt: 'Design a real-time one-on-one and group chat system supporting delivery/read receipts.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: real-time delivery, message ordering per conversation, offline delivery, receipts. Estimation: concurrent connections and messages/sec drive WebSocket server fleet size. API: sendMessage, fetchHistory, ack/read receipts. Data model: messages partitioned by conversation ID with a monotonic per-conversation sequence number. High-level: WebSocket gateway servers hold live connections, a presence/routing service maps user->gateway, messages persist to a durable store before fan-out. Deep dive: handling a recipient offline (queue + push notification), group chat fan-out cost, message ordering under gateway failover. Tradeoffs: strict ordering per conversation vs. horizontal scalability of the gateway layer.', companies: [3, 8] },
  { title: 'Design a distributed job scheduler', prompt: 'Design a system that runs scheduled and delayed jobs reliably across a fleet of workers.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: exactly-once-ish execution (at-least-once + idempotency in practice), delayed and cron-style scheduling, horizontal worker scaling. Estimation: jobs/sec and job duration distribution drive worker pool size. API: scheduleJob(payload, runAt/cron), cancelJob(id). Data model: jobs table with next-run-time index, a leased/claimed status to prevent double-pickup. High-level: a poller claims due jobs with a visibility timeout (lease), workers process and ack, unacked leases become reclaimable after timeout. Deep dive: leader election or sharded polling to avoid every instance scanning the whole table; handling worker crash mid-job (idempotent handlers, lease expiry). Tradeoffs: polling interval vs. scheduling precision; centralized scheduler (simpler, single point of contention) vs. sharded (scales further, more coordination complexity).' },
  { title: 'Design a web crawler', prompt: 'Design a scalable web crawler that discovers and fetches pages while respecting robots.txt and avoiding duplicate work.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: politeness (rate limits per domain, robots.txt), avoid re-crawling duplicates, horizontal scale. Estimation: target pages/day and average page size drive fetcher and storage capacity. API: seed URLs in, fetched documents out to a downstream indexer. Data model: a URL frontier (priority queue per domain) and a seen-URL set (bloom filter for scale) to dedupe. High-level: fetchers pull from per-domain queues (rate-limited), parse links, push new URLs back through a dedup filter into the frontier. Deep dive: bloom filter false-positive tradeoffs for the seen-set at scale; per-domain politeness via domain-sharded queues, not a single global queue. Tradeoffs: freshness (re-crawl frequency) vs. crawl budget; broad coverage vs. focused/prioritized crawling.' },
  { title: 'Design a video streaming platform', prompt: 'Design the upload-to-playback pipeline for a video platform (like a simplified YouTube).', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: reliable large-file upload, multi-resolution playback, low-latency global delivery. Estimation: uploads/day and average video length/resolution drive transcoding and storage capacity. API: initiateUpload (resumable), getPlaybackManifest(videoId). Data model: raw video in object storage, transcoded renditions per resolution, metadata in a relational/document store. High-level: chunked/resumable upload to object storage, an async transcoding pipeline produces adaptive-bitrate renditions (e.g. HLS/DASH), a CDN serves playback from edge caches. Deep dive: adaptive bitrate switching logic on the client; transcoding pipeline scaling (queue-driven workers) and handling partial failures per rendition. Tradeoffs: transcoding cost/latency (more renditions = better UX, more compute) vs. storage and processing budget.', companies: [3] },
  { title: 'Design a typeahead/autocomplete service', prompt: 'Design a low-latency search-as-you-type autocomplete service for a large query corpus.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: sub-100ms suggestions per keystroke, ranked by popularity/relevance, freshness of trending terms. Estimation: queries/sec and corpus size drive whether the index fits in memory on one node or must be sharded. API: getSuggestions(prefix, limit). Data model: a trie (or a precomputed prefix->top-K-suggestions map) built offline from query logs, refreshed periodically. High-level: client debounces keystrokes, hits a read-optimized service backed by the in-memory trie/map, with a CDN or edge cache for very common prefixes. Deep dive: precomputing top-K per prefix node to avoid a full subtree scan per request; incorporating recency/trending signals without rebuilding the whole structure. Tradeoffs: index freshness (rebuild frequency) vs. serving-latency guarantees; per-user personalization vs. shared global ranking.' },
  { title: 'Design a proximity/nearby-search service', prompt: 'Design a service that finds nearby points of interest (like nearby restaurants) given a user\'s location.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: fast radius/nearest-K queries over millions of points, reasonably fresh data. Estimation: query rate and point density drive indexing strategy choice. API: search(lat, lng, radius, filters). Data model: geohash or a quadtree/R-tree spatial index over point locations, enabling range queries without scanning every point. High-level: geohash-prefix range queries approximate a bounding box, refined with an exact distance filter on the candidate set. Deep dive: geohash boundary edge cases (nearby points with very different prefixes near a cell boundary) requiring neighbor-cell lookups; balancing index granularity against query fan-out. Tradeoffs: index rebuild cost for frequently-moving points (e.g. live driver locations) vs. static points of interest.' },
  { title: 'Design a leaderboard service', prompt: 'Design a real-time leaderboard supporting millions of players and frequent score updates.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: real-time rank queries (top-K and "my rank"), frequent score updates, scale to millions of entrants. Estimation: updates/sec and read/write ratio drive whether a sorted-set-style structure fits one node or must be sharded. API: updateScore(userId, score), getTopK(k), getRank(userId). Data model: a sorted-set (score-ordered) structure (e.g. Redis ZSET) giving O(log n) update and O(log n + k) top-K/rank queries. High-level: writes update the sorted set directly; reads query it directly for small scale, or from a periodically-refreshed cache for very high read volume. Deep dive: sharding the leaderboard by region/game-mode when a single sorted set can\'t hold the full player base; handling ties in ranking consistently. Tradeoffs: real-time exact rank (more write cost) vs. periodically-refreshed approximate rank (cheaper, staler).' },
  { title: 'Design a distributed message queue', prompt: 'Design a durable, ordered message queue (like a simplified Kafka topic-partition model) supporting multiple consumers.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: durability (no message loss), at-least-once delivery, ordering within a partition, horizontal scale. Estimation: messages/sec and retention window drive partition count and storage. API: publish(topic, key, payload), subscribe(topic, consumerGroup). Data model: an append-only log per partition, with each consumer group tracking its own read offset. High-level: producers hash a key to a partition for ordering guarantees within that key; consumers in a group each own a subset of partitions and track offsets independently, enabling replay. Deep dive: partition leader/replica failover without losing acknowledged writes (write quorum); consumer group rebalancing when a consumer joins/leaves. Tradeoffs: partition count (more parallelism, more per-partition ordering scope) vs. operational complexity of rebalancing and leader election.' },
  { title: 'Design a distributed lock service', prompt: 'Design a distributed lock service that multiple application instances can use to coordinate exclusive access to a resource.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: mutual exclusion across processes/machines, safety even under network partitions and client crashes. Estimation: lock acquisition rate and typical hold-time drive the coordination service\'s load. API: acquireLock(resource, ttl), releaseLock(resource, token), renewLock(resource, token). Data model: a lock record with an owner token and expiry, stored in a consensus-backed store (e.g. built on Raft/Paxos, or Redis with careful caveats). High-level: acquire is a conditional write (only succeeds if unheld or expired); a TTL bounds how long a crashed holder can block others; renewal extends the TTL for legitimately long operations. Deep dive: the classic "client pauses past its TTL, then resumes believing it still holds the lock" hazard (fencing tokens — a monotonically increasing token checked by the protected resource — mitigate this). Tradeoffs: a single-node lock service is simpler but a single point of failure; a consensus-backed one is more available/correct but adds latency and operational complexity.' },
  { title: 'Design a URL-based ad click aggregation pipeline', prompt: 'Design a system that aggregates billions of daily ad click events into near-real-time and historical reports.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: handle high event volume, near-real-time dashboards, accurate historical rollups (dedup/fraud-resistant). Estimation: clicks/sec and required dashboard latency drive the streaming vs. batch split. API: ingest(clickEvent), queryAggregate(dimensions, timeRange). Data model: raw events land in a durable log (e.g. a partitioned queue); pre-aggregated rollups by time bucket and dimension (ad, campaign, geo) in an OLAP-style store. High-level: a streaming layer computes approximate near-real-time aggregates (windowed counting) for dashboards; a batch layer periodically reprocesses raw events for exact, corrected historical rollups (lambda-architecture style). Deep dive: deduplicating retried/duplicate click events (idempotency keys per event); handling very late-arriving events in windowed aggregation. Tradeoffs: real-time approximate counts (fast, occasionally slightly off) vs. batch-corrected exact counts (accurate, higher latency).' },
  { title: 'Design a collaborative document editor', prompt: 'Design the backend for a Google-Docs-style collaborative text editor supporting simultaneous edits.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: multiple users editing the same document concurrently without conflicting/lost edits, low-latency propagation. Estimation: concurrent editors per document (usually small) and edit frequency drive the per-document coordination approach. API: applyEdit(docId, operation), subscribe(docId) for live updates. Data model: a sequence of operations (insert/delete at a position) per document, or a CRDT-based structure that merges concurrent edits deterministically. High-level: each client sends local operations to a per-document coordinator (or peer-to-peer via CRDTs), which transforms concurrent operations against each other (operational transformation) or merges them (CRDT) and broadcasts the resolved result to all connected clients. Deep dive: operational transformation\'s correctness complexity (transform functions must satisfy specific convergence properties) versus CRDTs\' simpler merge guarantees at the cost of larger per-character metadata overhead. Tradeoffs: OT (compact representation, complex transform logic) vs. CRDT (simpler merge logic, higher memory/network overhead per edit).' },
  { title: 'Design a log aggregation and search system', prompt: 'Design a system that ingests logs from thousands of services and supports fast full-text search over recent history.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: ingest high-volume logs reliably, support full-text and structured (field) search, retain recent data with fast queries and older data more cheaply. Estimation: logs/sec across the fleet and retention window drive ingestion and storage tiering. API: ingest(logLine, metadata), search(query, timeRange, filters). Data model: an inverted index (like Elasticsearch) over recent hot data, with older data rolled into cheaper cold storage (object storage) with a coarser index or none. High-level: log shippers batch and forward to an ingestion pipeline (queue-buffered for durability under backpressure), which indexes into the hot search cluster; a background job ages out old data to cold storage. Deep dive: index sharding strategy (by time range is common, since most queries are time-bounded) and handling a burst of logs from an incident spike without dropping data. Tradeoffs: retention length in the fast/searchable tier (cost) vs. how far back operators need to search quickly during an incident.' },
  { title: 'Design an API gateway', prompt: 'Design an API gateway that sits in front of many backend microservices, handling auth, rate limiting, and routing.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: request routing to the correct backend service, centralized auth/rate limiting, low added latency. Estimation: total request volume across all routed services drives the gateway fleet size. API: the gateway itself exposes the union of routed services\' public APIs. Data model: a routing table (path/host -> backend service), auth token validation rules, per-route rate limit config. High-level: incoming request is authenticated, rate-limit-checked, routed to the matching backend (often via service discovery), response passed back (optionally transformed). Deep dive: where auth token validation happens (gateway vs. downstream service) and how routing config changes propagate without a gateway restart; circuit-breaking a failing downstream service so it doesn\'t take the whole gateway down. Tradeoffs: a single shared gateway (simpler operations, single point of failure/bottleneck) vs. per-team gateways (more resilient, more duplicated logic to maintain).' },
  { title: 'Design a distributed cache layer', prompt: 'Design a distributed cache (like a Memcached/Redis cluster) used to reduce load on a primary database.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: low-latency get/set, horizontal scale, graceful handling of cache misses and node failure. Estimation: hot-key working-set size and read QPS drive cluster memory and node count. API: get(key), set(key, value, ttl), delete(key). Data model: key-value pairs sharded across cache nodes via consistent hashing. High-level: application checks cache first (cache-aside pattern), falls back to the database on a miss and populates the cache; writes typically invalidate or update the cache alongside the database write. Deep dive: cache stampede on a popular key\'s expiry (many concurrent misses hitting the database at once) mitigated with request coalescing or jittered TTLs; consistent hashing to minimize redistribution when nodes are added/removed. Tradeoffs: cache-aside (simple, but a moment of staleness/miss possible) vs. write-through (always consistent, adds write latency).' },
  { title: 'Design a payment processing system', prompt: 'Design the core of a payment processing system that charges customers and reliably records the outcome.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: exactly-once-semantics for charges (never double-charge), reliable record-keeping even if a downstream payment provider call fails ambiguously, auditability. Estimation: transactions/sec and provider call latency drive queueing/timeout design. API: createCharge(idempotencyKey, amount, paymentMethod). Data model: a charge record with a state machine (pending -> succeeded/failed), keyed by a client-supplied idempotency key, plus an immutable ledger of state transitions for audit. High-level: persist the charge intent before calling the external payment provider; on an ambiguous provider response (timeout), don\'t assume failure — reconcile via the provider\'s status-check API or webhook before retrying. Deep dive: handling the "did the provider actually charge the card?" ambiguity safely (never blindly retry a charge call without an idempotency key the provider itself honors); reconciliation jobs that periodically compare internal state against provider-reported state. Tradeoffs: synchronous provider calls (simpler, but ties up a request thread on a slow provider) vs. async with polling/webhooks (more resilient, more moving parts).', companies: [10] },
  { title: 'Design a ride-sharing dispatch system', prompt: 'Design the driver-rider matching and dispatch core of a ride-sharing app.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: match riders to nearby available drivers quickly, handle high-frequency location updates, fair/efficient dispatch. Estimation: concurrent active drivers/riders and location-update frequency drive the spatial index\'s update rate. API: requestRide(riderId, pickupLocation), updateDriverLocation(driverId, location), acceptRide(driverId, rideId). Data model: a spatial index (geohash/quadtree) of currently-available drivers\' locations, refreshed on each location ping. High-level: a rider request queries the spatial index for nearby available drivers, dispatches an offer to the best candidate(s), and the first acceptance wins (with a timeout to try the next candidate if none accept). Deep dive: handling near-simultaneous ride requests competing for the same driver (an offer/accept protocol with short timeouts, not a lock); balancing "nearest driver" against surge/fairness considerations. Tradeoffs: broadcasting to multiple nearby drivers at once (faster matches, wasted notifications) vs. sequential offering (fewer wasted notifications, slower matches).', companies: [4, 5] },
  { title: 'Design a distributed file storage service', prompt: 'Design an object storage service (like a simplified S3) that stores and serves large binary blobs reliably.', type: 'system_design', difficulty: 'hard', topic: 6, answer: 'Requirements: durability (survive disk/node failure without data loss), high availability, scale to huge object counts and sizes. Estimation: total storage volume and read/write throughput drive replication factor and node count. API: putObject(bucket, key, data), getObject(bucket, key), deleteObject(bucket, key). Data model: objects chunked and replicated across multiple storage nodes/racks, with metadata (bucket, key, chunk locations, checksums) in a separate metadata service. High-level: writes stripe/replicate chunks across nodes in different failure domains (racks/zones), reads fetch from the nearest healthy replica, background processes continuously verify checksums and re-replicate under-replicated chunks. Deep dive: erasure coding versus full replication tradeoffs for storage efficiency vs. reconstruction cost/complexity; metadata service scaling since it\'s consulted on every request. Tradeoffs: strong replication (higher storage cost, simpler recovery) vs. erasure coding (lower storage overhead, more CPU cost to reconstruct on failure).' },
  { title: 'Design a search autocomplete\'s trending-terms feature', prompt: 'Extend a search system to surface currently trending queries, updated with low latency as query volume shifts.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: near-real-time trending detection, resistant to noise from low-volume spikes, bounded compute cost. Estimation: query volume and desired trend-detection window (e.g. last 10 minutes) drive the streaming aggregation window size. API: getTrending(category, limit). Data model: a sliding-window count-min-sketch or exact counter per term per short time bucket, aggregated into a ranked "currently trending" set. High-level: a streaming layer counts query terms in rolling windows, periodically recomputing a top-K trending list; results are served from a small, frequently-refreshed cache rather than computed per request. Deep dive: distinguishing genuine trends from noise (a minimum absolute-count threshold, or comparing against a longer-baseline average to require significant relative lift). Tradeoffs: shorter windows (more responsive to real spikes, noisier) vs. longer windows (smoother, slower to reflect genuine breaking trends).' },
  { title: 'Design a feature flag platform', prompt: 'Design a feature flag service that supports targeted rollout, fast evaluation, auditability, and safe rollback across many applications.', type: 'system_design', difficulty: 'medium', topic: 6, answer: 'Requirements: low-latency flag evaluation, cohort targeting, percentage rollouts, audit trails, and instant rollback. Estimation: read-heavy evaluation traffic drives edge/cache strategy, while flag updates are comparatively rare. API: evaluateFlag(flagKey, context), create/update flag rules, and list audit history. Data model: flag definitions, targeting rules, rollout percentages, environment scopes, and immutable change events. High-level: a control plane stores and validates flag config, publishes versioned snapshots to SDKs or edge caches, and clients evaluate locally whenever possible to avoid a network hop on hot paths. Deep dive: deterministic hashing for percentage rollout stability; stale config handling with version TTLs and safe defaults. Tradeoffs: local evaluation is fast and resilient but may be briefly stale; centralized evaluation is easier to govern but adds latency and dependency risk.' },

  { title: 'Tell me about a difficult bug', prompt: 'Describe a difficult production or project bug you diagnosed and fixed.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Use STAR: establish impact and constraints, explain your diagnostic ownership and evidence, describe the focused fix and verification, quantify the result, and state what monitoring or process change prevented recurrence.' },
  { title: 'Disagreement with a teammate', prompt: 'Tell me about a technical disagreement and how you resolved it.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Explain the legitimate competing goals, how you clarified assumptions and gathered evidence, how the team chose a decision rule or experiment, and the outcome. Show respect, willingness to change your view, and commitment after the decision.' },
  { title: 'A project that failed', prompt: 'Describe a project or decision that did not work and what you learned.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Own your contribution without blaming others, identify the mistaken assumption or missed signal, describe the corrective action, and demonstrate a specific later behavior changed by the lesson.' },
  { title: 'Prioritize under a deadline', prompt: 'How have you handled several important tasks with an immovable deadline?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Describe how you identified the critical outcome, surfaced dependencies and risks, negotiated scope using impact and effort, communicated tradeoffs early, and preserved a minimum quality bar. End with the measurable outcome and retrospective improvement.' },

  // MOM-058: Behavioral prompts batch 1 (toward the plan's 60-prompt Gate-3
  // target). Answers are STAR-structuring guidance for the user's own story, not
  // a fabricated personal anecdote — actual stories belong in the Story Bank
  // (plan §7.5), which links to these prompts once built (MOM-063-067).
  { title: 'Owning a project end to end', prompt: 'Tell me about a time you took full ownership of a project from start to finish.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Situation/Task: describe the scope and why ownership fell to you. Action: emphasize decisions you made unprompted, risks you proactively surfaced, and how you kept stakeholders informed without being asked. Result: quantify the outcome and name one thing you would still improve.' },
  { title: 'Convincing skeptical stakeholders', prompt: 'Describe a time you had to convince a skeptical stakeholder or team to adopt your approach.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: show you understood their concern before pitching your position (not just repeating your argument louder), used evidence or a small experiment to build trust incrementally, and adapted your approach based on their pushback. Result: describe the actual decision reached and whether the relationship improved for future collaboration.' },
  { title: 'Mentoring a struggling teammate', prompt: 'Tell me about a time you helped a struggling teammate improve.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you diagnosed the specific gap (skill, confidence, unclear expectations) rather than assuming, the concrete support you gave (pairing, feedback cadence, scoped tasks), and how you balanced helping them with your own workload. Result: describe the measurable improvement and how you knew it was sustained, not one-off.' },
  { title: 'Receiving critical feedback', prompt: 'Describe a time you received difficult feedback about your work or behavior. How did you respond?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: show you didn\'t get defensive first — you asked clarifying questions to understand the specific behavior and impact, not just the label. Result: describe a concrete change you made afterward and how you verified it landed (asked the same person later, or saw the outcome improve).' },
  { title: 'Giving difficult feedback', prompt: 'Tell me about a time you had to give a teammate feedback they didn\'t want to hear.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you made the feedback specific and behavior-focused (not personality-focused), chose a private and timely setting, and invited their perspective rather than just delivering a verdict. Result: describe how they responded and what changed afterward, including if it didn\'t go perfectly and what you\'d do differently.' },
  { title: 'Working with incomplete requirements', prompt: 'Describe a project where the requirements were vague or kept changing. How did you handle the ambiguity?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: show how you reduced ambiguity actively — asked targeted questions, proposed a concrete interpretation and got early sign-off, or built a small piece first to validate direction before over-investing. Result: describe how this avoided wasted work compared to charging ahead on assumptions.' },
  { title: 'Pushing back on a request', prompt: 'Tell me about a time you pushed back on a request from your manager or a stakeholder.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: emphasize that you pushed back with reasoning and alternatives (not just refusal), grounded in impact/risk/effort, and stayed professional even if they didn\'t immediately agree. Result: describe the actual outcome — whether they changed course, you found a compromise, or you executed their original ask anyway once you understood their constraints.' },
  { title: 'Balancing speed and quality', prompt: 'Describe a time you had to decide between shipping fast and doing it "right."', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe the specific tradeoff you evaluated (what "cutting corners" would actually cost later vs. the value of speed now), and how you made the shortcut deliberate and reversible (e.g. explicit tech debt ticket, feature-flagged rollout) rather than silent. Result: state whether the tradeoff paid off and what you\'d repeat or avoid next time.' },
  { title: 'Handling an on-call incident', prompt: 'Walk me through a production incident you responded to, including the aftermath.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe your triage process (assessing blast radius before diving into root cause), how you communicated status during the incident, and the immediate mitigation versus the real fix. Result: describe the postmortem outcome — what changed in monitoring, runbooks, or architecture so the same class of incident is less likely or easier to catch next time.' },
  { title: 'Learning a new technology under pressure', prompt: 'Tell me about a time you had to quickly learn an unfamiliar technology or domain to deliver something.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe your learning strategy (reading source/docs vs. asking an expert vs. building a small spike) and how you validated your understanding before committing to a larger implementation. Result: describe the delivered outcome and how confident you are now versus then.' },
  { title: 'Navigating conflicting priorities across teams', prompt: 'Describe a time two teams or stakeholders wanted conflicting things from you at once.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: show you surfaced the conflict explicitly rather than silently picking one side, brought both parties (or their represented interests) into a conversation about tradeoffs, and either found a sequencing/compromise or escalated to someone who could make the call. Result: describe the resolution and whether both sides felt heard even if they didn\'t both get what they wanted.' },
  { title: 'Advocating for a technical investment', prompt: 'Tell me about a time you convinced leadership to invest in technical debt or infrastructure work with no immediate feature payoff.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you translated the technical problem into business terms (velocity impact, incident frequency, hiring/onboarding cost) rather than a purely technical pitch, and how you scoped a concrete, boundable proposal instead of an open-ended ask. Result: describe what was approved, what was delivered, and the measurable improvement afterward.' },
  { title: 'Recovering from a mistake you caused', prompt: 'Describe a mistake you made that had real consequences. How did you handle it?', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: emphasize you surfaced the mistake yourself promptly rather than hoping it went unnoticed, focused first on mitigating impact before assigning any blame (including to yourself), and communicated clearly to affected parties. Result: describe the concrete process or habit change that followed, and how you\'ve since verified you (or the team) don\'t repeat it.' },
  { title: 'Working with a difficult teammate', prompt: 'Tell me about a time you had to work closely with someone whose working style clashed with yours.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you tried to understand their perspective/constraints before assuming bad intent, and a specific adjustment you made (communication style, meeting cadence, explicit written agreements) to make collaboration work. Result: describe whether the relationship improved and what you learned about adapting your own style.' },
  { title: 'Simplifying a complex technical explanation', prompt: 'Describe a time you had to explain a complex technical topic to a non-technical audience.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you identified what the audience actually needed to decide or understand (not a full technical download), used an analogy or concrete example grounded in their world, and checked their understanding rather than assuming it landed. Result: describe the decision or outcome that followed and any feedback on your communication.' },
  { title: 'Making a decision with incomplete data', prompt: 'Tell me about an important decision you had to make without all the information you wanted.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you identified the minimum information needed to decide safely (versus nice-to-have), set an explicit deadline for gathering it, and made the call with a clear rationale rather than indefinitely stalling. Result: describe the outcome and, if it turned out wrong, how quickly you detected and corrected course.' },
  { title: 'Improving a broken process', prompt: 'Describe a time you identified and fixed a broken or inefficient team process.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you diagnosed the actual root cause of the inefficiency (not just a surface symptom), proposed a change with buy-in from the people affected (not unilaterally imposed), and measured whether it actually helped. Result: state the concrete before/after metric and whether the change stuck after you stopped actively pushing it.' },
  { title: 'Handling scope creep', prompt: 'Tell me about a project where scope kept expanding. How did you manage it?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you made the scope changes visible (a running list, re-estimation) rather than silently absorbing them, and how you negotiated tradeoffs (cut something else, extend timeline, or explicitly accept the new scope with stakeholders\' eyes open). Result: describe how the project actually landed and what you\'d do differently to prevent creep earlier.' },
  { title: 'Leading without formal authority', prompt: 'Describe a time you led an initiative or drove a decision without having formal authority over the people involved.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: emphasize influence through clarity, evidence, and trust-building rather than positional authority — how you got buy-in, delegated meaningfully, and gave credit to contributors. Result: describe the outcome and what it revealed about your ability to lead peers.' },
  { title: 'Saying no to protect quality or scope', prompt: 'Tell me about a time you said no to a feature, request, or shortcut that you believed was the wrong call.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe the reasoning you gave (not just refusal), and how you offered an alternative path forward rather than only blocking. Result: describe how it was received and whether the underlying concern was validated later.' },
  { title: 'Adapting to an unexpected organizational change', prompt: 'Describe a time your team or project was significantly affected by an unexpected reorg, pivot, or priority shift.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you processed the change constructively (versus resisting or disengaging) and what you did to keep yourself and, if relevant, your team productive and informed during the transition. Result: describe where things landed and what you learned about handling change.' },
  { title: 'Working through a disagreement with your manager', prompt: 'Tell me about a time you disagreed with a decision your manager made.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you raised the disagreement privately and constructively, with specific reasoning, and how you distinguished "disagree and discuss" from "disagree and commit" once a final call was made. Result: describe the outcome and how the working relationship was afterward.' },
  { title: 'Delivering bad news to a stakeholder', prompt: 'Describe a time you had to tell a stakeholder or customer that something would be late, broken, or not delivered as promised.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you communicated proactively (before they found out another way) with a clear explanation, concrete revised plan, and ownership rather than excuses. Result: describe how the relationship was preserved or repaired and what changed in your own planning/communication going forward.' },
  { title: 'Balancing competing team member needs', prompt: 'Tell me about a time you had to balance the needs of multiple team members with conflicting goals or workloads.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you gathered each person\'s actual constraint (not assumed), looked for a solution that didn\'t just favor the loudest voice, and communicated the reasoning behind whatever tradeoff you landed on. Result: describe how the team responded and whether it held up over time.' },
  { title: 'Contributing to a hiring or interviewing process', prompt: 'Describe your experience interviewing or evaluating candidates. What did you learn about assessing people fairly?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe a specific calibration challenge you noticed (inconsistent bar across interviewers, bias toward candidates similar to yourself) and what you did about it — structured rubrics, calibration sessions, focusing on evidence over gut feel. Result: describe how it improved decision quality or consistency.' },
  { title: 'Balancing personal growth with team needs', prompt: 'Tell me about a time you had to choose between an opportunity that was good for your growth and one that was better for the team.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you weighed the tradeoff honestly rather than rationalizing self-interest as team benefit (or vice versa), and whether you communicated the tension openly with your manager/team. Result: describe what you chose and how you feel about it in hindsight.' },
  { title: 'Improving code review culture', prompt: 'Describe a time you influenced how your team did code review, either by giving or receiving reviews.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe a specific friction point (reviews too slow, too nitpicky, inconsistent standards) and the concrete change you proposed (review SLAs, a style guide, focusing comments on correctness/design over nits). Result: describe the measurable effect on review turnaround, code quality, or team morale.' },
  { title: 'Dealing with an underperforming dependency or vendor', prompt: 'Tell me about a time a third-party service, library, or team you depended on caused problems for your work.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you diagnosed whether the problem was really the dependency or your integration with it, how you mitigated impact in the short term (workaround, fallback), and how you engaged the dependency owner constructively. Result: describe the resolution and any lasting change to how you depend on external systems.' },
  { title: 'Balancing perfectionism with delivery', prompt: 'Describe a time your own standards for quality conflicted with a need to ship.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you distinguished must-have quality bars from nice-to-have polish, and how you made the cut explicit (documented follow-up, not silently abandoned) rather than either blowing the deadline or shipping something you were ashamed of. Result: describe the outcome and whether the deferred work actually got done later.' },
  { title: 'Championing an unpopular but correct technical decision', prompt: 'Tell me about a time you advocated for a technically correct but organizationally unpopular decision.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you built the case with concrete evidence and addressed the real (not dismissed) concerns behind the unpopularity, rather than just asserting you were right. Result: describe whether you succeeded, and if not, how you handled being overruled while staying constructive.' },
  { title: 'Navigating a layoff, downsizing, or team restructuring', prompt: 'Describe how you handled a period of team instability, layoffs, or significant restructuring.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you stayed focused on what was in your control (your own work quality, supporting remaining teammates) rather than spiraling, and any concrete steps you took to help the team stabilize. Result: describe what you learned about resilience and what, if anything, you\'d do differently.' },
  { title: 'Improving onboarding for new team members', prompt: 'Tell me about a time you improved the onboarding experience for a new hire or new team member.', type: 'behavioral', difficulty: 'easy', topic: 7, answer: 'Action: describe the specific gap you noticed (missing docs, unclear first tasks, no clear point of contact) and what you built or changed (a starter guide, a buddy system, a curated first-week task list). Result: describe how the next new hire\'s ramp-up compared, ideally with some concrete signal (time to first PR, self-reported confidence).' },
  { title: 'Handling a request you believed was unethical or unsafe', prompt: 'Describe a time you were asked to do something you felt was ethically questionable or technically unsafe (e.g. skip a security review, misrepresent data).', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you raised the concern clearly and specifically (not vaguely uncomfortable), proposed an alternative that addressed the underlying business need, and, if necessary, escalated appropriately. Result: describe the outcome and reinforce that you\'d handle it the same way again — interviewers want to see the principle held, not just the specific incident.' },
  { title: 'Balancing multiple stakeholders with different technical literacy', prompt: 'Tell me about a project where you had to keep both highly technical and non-technical stakeholders aligned.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you tailored communication depth per audience (detailed design docs for engineers, outcome-focused updates for executives) without creating two conflicting narratives. Result: describe how alignment was maintained and any friction point you had to specifically resolve.' },

  // MOM-059: Behavioral prompts batch 2 (closes the gap to the plan's 60-prompt target).
  { title: 'Estimating work you\'d never done before', prompt: 'Describe a time you had to estimate effort for work you had no prior experience with.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you reduced estimation risk — a quick spike/prototype to ground the estimate in evidence, breaking the work into smaller pieces to estimate independently, and communicating your confidence level (not false precision). Result: describe how close the estimate was and what you\'d do differently next time.' },
  { title: 'Handling a public failure or outage in front of customers', prompt: 'Tell me about a time something you built failed visibly in front of customers or leadership.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you stayed composed and focused on fixing/communicating rather than defending yourself, and how you handled the immediate aftermath (customer communication, internal accountability). Result: describe the longer-term outcome, including how it affected trust and what changed afterward.' },
  { title: 'Turning around a low-performing team or project', prompt: 'Describe a time you helped turn around a struggling project or underperforming team.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you diagnosed the actual root causes (unclear goals, skill gaps, morale, process) rather than assuming one obvious explanation, and the specific interventions you drove. Result: quantify the turnaround and describe what you learned about diagnosing team health.' },
  { title: 'Making a build-vs-buy decision', prompt: 'Tell me about a time you had to decide whether to build something in-house or use a third-party solution.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe the criteria you weighed (cost, control, time-to-market, long-term maintenance burden, vendor lock-in risk) and how you validated assumptions before committing. Result: describe the decision and whether it held up over time, including anything you\'d weigh differently now.' },
  { title: 'Working effectively across time zones or remotely', prompt: 'Describe a time you had to collaborate effectively with a distributed or remote team across time zones.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe specific practices you used to reduce friction from asynchronous communication (written design docs over meetings, clear decision logs, deliberate overlap-hour usage) and how you built trust without daily in-person contact. Result: describe the outcome and what you learned about remote collaboration.' },
  { title: 'Advocating for user needs against internal pressure', prompt: 'Tell me about a time you pushed back on an internal decision because it would hurt the end user experience.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you represented the user\'s perspective with evidence (data, user feedback, usability concerns) rather than just opinion, balanced against legitimate business constraints. Result: describe the outcome and whether the user-facing concern was ultimately addressed.' },
  { title: 'Balancing innovation with proven approaches', prompt: 'Describe a time you chose a new/experimental technology or approach over a proven one, or vice versa.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe your actual risk assessment (what happens if the new approach fails, how you\'d detect that early, what fallback existed) rather than choosing based on excitement or habit alone. Result: describe the outcome and whether your risk assessment proved accurate.' },
  { title: 'Working through imposter syndrome or self-doubt', prompt: 'Tell me about a time you doubted your ability to handle a task or role, and how you worked through it.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe concrete steps you took rather than just "pushing through" — breaking the intimidating task into smaller validated steps, seeking specific feedback, or finding a mentor/resource. Result: describe the outcome and what you\'d tell someone else facing the same doubt.' },
  { title: 'Standing up for a junior teammate\'s idea', prompt: 'Describe a time a more junior teammate had a good idea that wasn\'t being taken seriously, and what you did.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you amplified their contribution appropriately (crediting them directly, helping them present it effectively) rather than taking it over or just quietly agreeing without acting. Result: describe the outcome for the idea and for that teammate\'s confidence/standing on the team.' },
  { title: 'Recovering trust after a broken commitment', prompt: 'Tell me about a time you failed to deliver on a commitment and had to rebuild trust afterward.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe how you acknowledged the miss directly rather than minimizing it, and the concrete, sustained behavior change (not just an apology) that followed. Result: describe how you know trust was rebuilt — a specific signal, not just a feeling.' },
  { title: 'Making a tradeoff between short-term and long-term value', prompt: 'Describe a time you had to choose between a solution that solved the immediate problem and one that was better long-term.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you quantified or at least articulated the long-term cost of the short-term choice, and how you made that tradeoff visible to whoever needed to sign off on it, rather than deciding unilaterally and silently. Result: describe which you chose and how it played out.' },
  { title: 'Improving a metric you were accountable for', prompt: 'Tell me about a time you were responsible for improving a specific metric (performance, reliability, conversion, etc.).', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you diagnosed what was actually driving the metric (data investigation, not guessing) before proposing changes, and how you validated each change\'s actual impact (A/B test, before/after comparison) rather than assuming it worked. Result: quantify the improvement and note any change that surprisingly didn\'t help.' },
  { title: 'Navigating a merger, acquisition, or major tech migration', prompt: 'Describe your experience working through a major organizational or technical migration (e.g. an acquisition, platform migration, or vendor switch).', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe a specific challenge from the transition (conflicting systems/processes, uncertainty, migration risk) and the concrete steps you took to manage it responsibly. Result: describe the outcome and what you learned about managing change at scale.' },
  { title: 'Setting boundaries to protect focus or well-being', prompt: 'Tell me about a time you had to set a boundary (around scope, hours, or responsibilities) to protect your effectiveness or well-being.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you communicated the boundary professionally and with reasoning (not just refusal), and how you ensured the underlying need was still met some other way. Result: describe how it was received and whether you\'d set the same boundary again.' },
  { title: 'Improving cross-team documentation or knowledge sharing', prompt: 'Describe a time poor documentation or tribal knowledge caused a problem, and what you did about it.', type: 'behavioral', difficulty: 'easy', topic: 7, answer: 'Action: describe the specific gap (a key process living only in one person\'s head, outdated docs causing repeated mistakes) and the concrete artifact or process you created to close it. Result: describe how it changed things for the next person who needed that knowledge.' },
  { title: 'Delivering under resource constraints', prompt: 'Tell me about a time you had to deliver results with significantly fewer resources (people, budget, time) than you felt you needed.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe the specific tradeoffs you made explicit (scope cuts, phased delivery, automating what would have needed more headcount) rather than just working longer hours as the only lever. Result: describe what was delivered and what was consciously deferred, and how that was communicated.' },
  { title: 'Championing accessibility or inclusive design', prompt: 'Describe a time you advocated for accessibility, internationalization, or another often-overlooked user need.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you made the case in terms the team/business would act on (user impact, legal/compliance risk, market reach) rather than treating it as a purely moral appeal, and what you actually changed. Result: describe the concrete outcome and any resistance you had to work through.' },
  { title: 'Handling repeated interruptions to planned work', prompt: 'Tell me about a time constant interruptions (support requests, urgent bugs, ad-hoc asks) threatened your planned work.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe a systemic fix you pushed for (dedicated on-call rotation, triage process, protected focus time) rather than just personally absorbing the chaos indefinitely. Result: describe whether planned work throughput actually improved and how you measured it.' },
  { title: 'Making an unpopular but necessary staffing or scope call', prompt: 'Describe a time you had to make a difficult call about people or scope that you knew wouldn\'t be popular.', type: 'behavioral', difficulty: 'hard', topic: 7, answer: 'Action: describe the reasoning process you used to reach the decision and how you communicated it directly and respectfully to those affected, rather than avoiding the conversation. Result: describe the outcome and how you handled any fallout.' },
  { title: 'Contributing to a postmortem or blameless retro', prompt: 'Tell me about your role in a postmortem or retrospective after something went wrong.', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe how you kept the discussion focused on systemic/process causes rather than individual blame, and a specific concrete action item you drove to completion afterward (not just discussed). Result: describe whether that action item actually prevented a recurrence.' },
  { title: 'Adjusting your communication style for different audiences', prompt: 'Describe a time you had to adjust how you communicated based on who you were talking to (e.g. a skip-level, a new grad, an external partner).', type: 'behavioral', difficulty: 'easy', topic: 7, answer: 'Action: describe the specific adjustment you made (level of detail, formality, framing around their priorities) and why it mattered for that audience. Result: describe how the interaction went and what you learned about reading your audience.' },
  { title: 'Balancing multiple concurrent projects', prompt: 'Tell me about a time you were responsible for multiple significant projects at once. How did you keep them all moving?', type: 'behavioral', difficulty: 'medium', topic: 7, answer: 'Action: describe your actual system for tracking and context-switching (not just "I stayed organized") — how you decided what got attention each day, and how you communicated status/risk across all of them without dropping any. Result: describe how all the projects ultimately landed.' },

  { title: 'CUDA memory coalescing', prompt: 'Explain memory coalescing in CUDA and how poor access patterns affect kernel throughput.', type: 'hpc', difficulty: 'hard', topic: 3, answer: 'Coalescing lets adjacent threads access adjacent global memory so the hardware can combine requests into fewer memory transactions. Strided or divergent access patterns increase transactions, reduce bandwidth utilization, and can dominate kernel time. Improve layout, tiling, shared memory usage, and thread/block mapping.', roleTags: ['hpc-gpu-engineer'], areaTags: ['domain_knowledge'], patternTags: ['cuda', 'memory hierarchy', 'performance'] },
  { title: 'MPI versus shared-memory parallelism', prompt: 'Compare MPI and OpenMP. When would you choose each in a high-performance application?', type: 'hpc', difficulty: 'medium', topic: 3, answer: 'MPI is explicit distributed-memory message passing and fits multi-node workloads. OpenMP is shared-memory threading and fits one-node parallel loops or task parallelism. Real HPC codes often combine MPI across nodes and OpenMP or CUDA inside a node.', roleTags: ['hpc-gpu-engineer'], areaTags: ['domain_knowledge'], patternTags: ['mpi', 'openmp', 'parallel computing'] },
  { title: 'C++ RAII and exception safety', prompt: 'How does RAII improve resource safety in C++? Explain basic, strong, and no-throw exception guarantees.', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'RAII ties resource lifetime to object lifetime so destructors release memory, locks, files, and handles on all exits. Basic guarantee preserves invariants, strong guarantee commits atomically or rolls back, and no-throw guarantee promises an operation will not throw.', roleTags: ['hpc-gpu-engineer', 'quant-swe'], areaTags: ['language_runtime'], patternTags: ['c++', 'raii', 'exception safety'] },
  { title: 'Expected value with stopping', prompt: 'A game pays based on repeated coin flips until a stopping condition. How would you derive the expected payout?', type: 'quant', difficulty: 'hard', topic: 2, answer: 'Define states, write recurrence equations for expected value from each state, apply boundary conditions at stopping states, then solve the system. Check convergence and whether optional stopping assumptions apply.', roleTags: ['quant-swe'], areaTags: ['domain_knowledge'], patternTags: ['probability', 'expected value', 'recurrence'] },
  { title: 'Design a backtesting engine', prompt: 'Design a backtesting engine for trading strategies, including data ingestion, execution simulation, risk metrics, and reproducibility.', type: 'quant', difficulty: 'hard', topic: 6, answer: 'Separate data ingestion, strategy interface, execution simulator, portfolio accounting, and metric generation. Handle corporate actions, latency/slippage assumptions, transaction costs, deterministic replay, and experiment metadata.', roleTags: ['quant-swe'], areaTags: ['projects'], patternTags: ['backtesting', 'trading', 'system design'] },
  { title: 'Low-latency order book updates', prompt: 'How would you represent and update a limit order book for low-latency market data processing?', type: 'quant', difficulty: 'hard', topic: 0, answer: 'Use cache-friendly structures keyed by price levels, maintain best bid/ask pointers, apply incremental updates in sequence, detect gaps, and avoid allocation on the hot path. Measure latency percentiles and correctness under replay.', roleTags: ['quant-swe'], areaTags: ['system_design'], patternTags: ['latency', 'market data', 'data structures'] },

  // MOM-052: CS Fundamentals batch 1 (toward the plan's 150-item Gate-3 target).
  // Original questions written for this app across OS, networking, databases,
  // concurrency, computer architecture, ML fundamentals, OOP, JS/TS, Node.js,
  // backend, and C++ — the plan §8.2 scope for this domain.
  { title: 'Thread scheduling and starvation', prompt: 'How can a naive priority scheduler cause starvation, and what techniques prevent it?', type: 'os', difficulty: 'medium', topic: 3, answer: 'A strict priority scheduler can let low-priority threads wait indefinitely if higher-priority work keeps arriving. Aging (gradually raising waiting threads\' effective priority), priority inheritance for lock holders, and fair queuing / round-robin time slices bound worst-case wait time.' },
  { title: 'Copy-on-write and fork()', prompt: 'Explain how copy-on-write makes fork() cheap, and what triggers an actual page copy.', type: 'os', difficulty: 'medium', topic: 3, answer: 'fork() initially shares the parent\'s physical pages with the child, marking them read-only; both processes\' page tables point at the same frames. A write to a shared page traps into the kernel, which allocates a new frame, copies the data, and updates that process\'s page table entry — so copying is deferred until (and unless) it is actually needed.' },
  { title: 'File system journaling', prompt: 'What problem does journaling solve for file systems, and what is the tradeoff?', type: 'os', difficulty: 'medium', topic: 3, answer: 'Journaling writes pending metadata (and optionally data) changes to a sequential log before applying them in place, so a crash mid-write can be recovered by replaying or discarding the incomplete journal entry instead of leaving the filesystem in an inconsistent state. The tradeoff is extra write I/O (writing twice) for significantly better crash consistency.' },
  { title: 'Context switch cost', prompt: 'What makes a context switch expensive, beyond just saving and restoring registers?', type: 'os', difficulty: 'medium', topic: 3, answer: 'Register save/restore itself is fast, but a context switch also invalidates CPU caches and the TLB (translation lookaside buffer) for the new process\'s address space, causing a burst of cache/TLB misses as the new process "warms up" its working set. This is why reducing context switch frequency (larger time slices, thread pooling) matters for throughput-sensitive workloads.' },
  { title: 'Memory-mapped files', prompt: 'When would you use mmap() instead of read()/write(), and what are the risks?', type: 'os', difficulty: 'medium', topic: 3, answer: 'mmap() maps a file directly into the process\'s address space, letting the OS page it in on demand and avoiding an explicit copy into a user buffer — useful for large files accessed randomly or shared between processes. Risks include SIGBUS on I/O errors during access (rather than a clean error return) and subtler behavior around file truncation or extension while mapped.' },
  { title: 'TCP vs UDP tradeoffs', prompt: 'When would you choose UDP over TCP for a networked application?', type: 'networking', difficulty: 'medium', topic: 4, answer: 'UDP fits latency-sensitive or loss-tolerant workloads — real-time video/audio, gaming state updates, DNS queries — where TCP\'s retransmission and in-order delivery would add lag re-delivering stale data. TCP fits anything requiring guaranteed, ordered, complete delivery (file transfer, API calls, most web traffic).' },
  { title: 'TLS handshake overview', prompt: 'Walk through what happens during a TLS 1.2/1.3 handshake at a high level.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Client and server negotiate a cipher suite, the server presents a certificate (verified against a trusted CA chain), and both sides derive a shared symmetric session key via a key-exchange algorithm (e.g. ephemeral Diffie-Hellman) without transmitting it in plaintext. TLS 1.3 reduces this to one round trip (versus two in 1.2) by making stronger assumptions about supported cipher suites upfront.' },
  { title: 'DNS resolution path', prompt: 'Trace what happens when a browser resolves a domain name it has never seen before.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'The OS checks its local cache/hosts file, then queries a configured recursive resolver, which — if uncached — walks the hierarchy: root servers point to TLD servers (e.g. .com), which point to the domain\'s authoritative nameservers, which return the actual record. The recursive resolver caches the result per its TTL for future queries.' },
  { title: 'HTTP/2 multiplexing', prompt: 'What problem does HTTP/2 multiplexing solve that HTTP/1.1 had?', type: 'networking', difficulty: 'medium', topic: 4, answer: 'HTTP/1.1 serializes requests per TCP connection (or requires opening several parallel connections, each with its own handshake/slow-start cost) and suffers head-of-line blocking when one response is slow. HTTP/2 multiplexes many request/response streams over a single connection using framed messages, so a slow response no longer blocks unrelated ones on that connection.' },
  { title: 'CDN cache invalidation', prompt: 'How would you safely invalidate cached content across a CDN when the origin changes?', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Prefer versioned/content-hashed URLs (cache-busting by filename) for static assets so old cached copies simply become unreferenced, avoiding invalidation races entirely. For content that must be invalidated in place, use the CDN\'s purge API scoped as narrowly as possible, and set short TTLs plus stale-while-revalidate for content that changes unpredictably.' },
  { title: 'Database normalization tradeoffs', prompt: 'When would you intentionally denormalize a schema, and what do you give up?', type: 'database', difficulty: 'medium', topic: 2, answer: 'Denormalize (duplicate data, precompute aggregates) when read-heavy query patterns need to avoid expensive joins/aggregations at request time — e.g. a materialized "order total" column. The tradeoff is write complexity: every place that duplicates data must stay in sync, usually via triggers, application logic, or accepted eventual consistency.' },
  { title: 'B-tree vs hash index', prompt: 'When would a hash index outperform a B-tree index, and when would it fail?', type: 'database', difficulty: 'medium', topic: 2, answer: 'A hash index gives O(1) equality lookups and can beat a B-tree\'s O(log n) for exact-match queries. It fails for range queries, ordering, or prefix matching, since hash values don\'t preserve any relationship to the original key\'s ordering — a B-tree supports all of those by maintaining sorted order.' },
  { title: 'Write-ahead logging', prompt: 'Why do most relational databases use write-ahead logging (WAL) instead of writing data pages directly?', type: 'database', difficulty: 'medium', topic: 2, answer: 'WAL requires that a change\'s log record be durably written before the change is considered committed, but the actual data pages can be flushed to disk lazily and out of order. This turns crash recovery into "replay the log from the last checkpoint" instead of requiring every commit to force a random-access data-page write, which is much slower.' },
  { title: 'N+1 query problem', prompt: 'Explain the N+1 query problem and two ways to fix it.', type: 'database', difficulty: 'easy', topic: 2, answer: 'Fetching a list of N parent rows and then issuing one additional query per row to fetch related data results in N+1 total queries instead of a small constant number. Fix with eager loading (a single JOIN or an IN-clause batch query for all related rows at once) or a dedicated batching/dataloader layer that coalesces per-row requests within a request cycle.' },
  { title: 'Read replicas and replication lag', prompt: 'What problems can replication lag cause for an application reading from a read replica right after a write?', type: 'database', difficulty: 'medium', topic: 2, answer: 'A user who just wrote data (e.g. posted a comment) may read from a lagging replica and not see their own write, producing a confusing "it disappeared" experience. Mitigations: read-your-writes consistency (route the immediate follow-up read to the primary, or track a session\'s last-written position and wait for the replica to catch up to it), or accept eventual consistency where the UX tolerates it.' },
  { title: 'Race condition vs data race', prompt: 'Distinguish a data race from a race condition. Can you have one without the other?', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'A data race is specifically two threads accessing the same memory concurrently with at least one write and no synchronization — a well-defined technical term, often undefined behavior in languages like C++. A race condition is a broader correctness bug where the outcome depends on timing/ordering, which can happen even with proper synchronization (e.g. check-then-act logic across two separately-locked critical sections). You can have a race condition without a data race, and a data race is almost always also a race condition.' },
  { title: 'Deadlock vs livelock', prompt: 'Contrast deadlock and livelock with a concrete example of each.', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'Deadlock: two threads each hold a lock the other needs and both block forever waiting (classic circular wait). Livelock: threads keep actively responding to each other (e.g. both repeatedly back off and retry in lockstep) without making progress — they\'re not blocked, just perpetually un-progressing. Livelock is often introduced by naive deadlock-avoidance retry logic.' },
  { title: 'Memory model and reordering', prompt: 'Why can a write in one thread appear "out of order" to another thread without synchronization, even on a single CPU?', type: 'concurrency', difficulty: 'hard', topic: 9, answer: 'Compilers and CPUs are free to reorder independent instructions and buffer writes (store buffers, cache coherence protocols) as long as single-threaded behavior is preserved — but that reordering is observable across threads without a memory barrier. Synchronization primitives (locks, atomics with the right memory ordering, volatile in some languages) insert the necessary barriers/fences so one thread\'s writes become visible to another in the intended order.' },
  { title: 'Optimistic concurrency with atomics', prompt: 'Explain compare-and-swap (CAS) and how it enables lock-free data structures.', type: 'concurrency', difficulty: 'hard', topic: 9, answer: 'CAS atomically checks whether a memory location still holds an expected value and, if so, swaps in a new value in one indivisible hardware operation; if another thread changed it first, CAS fails and the caller retries with a fresh read. Lock-free structures build on this "read, compute new value, CAS, retry on failure" loop instead of taking a lock, avoiding blocking but requiring careful handling of the ABA problem.' },
  { title: 'Thread pool sizing', prompt: 'How would you decide the right thread pool size for a CPU-bound versus an I/O-bound workload?', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'CPU-bound work benefits from a pool size close to the number of physical cores — more threads than that just adds context-switch overhead with no throughput gain. I/O-bound work benefits from a larger pool (threads spend most time blocked waiting on I/O, not consuming CPU), sized roughly by expected concurrency and wait-time ratio, or better, replaced with an async/non-blocking I/O model entirely.' },
  { title: 'CPU cache lines and false sharing', prompt: 'What is false sharing, and how do you avoid it?', type: 'computer_architecture', difficulty: 'hard', topic: 10, answer: 'False sharing happens when independent variables used by different threads happen to sit on the same cache line; a write by one thread invalidates the whole line, forcing the other thread\'s CPU to reload it even though it never touched the written variable. Avoid it by padding/aligning hot per-thread variables to separate cache lines (typically 64 bytes) so unrelated writes don\'t contend.' },
  { title: 'Branch prediction and misprediction cost', prompt: 'Why can an "if" branch that\'s hard to predict be significantly slower than one that is, even with identical instruction counts?', type: 'computer_architecture', difficulty: 'medium', topic: 10, answer: 'Modern CPUs speculatively execute instructions past a branch based on a prediction, to keep the pipeline full. A misprediction requires flushing the speculatively-executed work and restarting from the correct path, costing many cycles (a full pipeline flush) — far more than the branch instruction itself would cost if predicted correctly. Sorting data or restructuring branches to be more predictable can meaningfully speed up hot loops.' },
  { title: 'Memory hierarchy and locality', prompt: 'Explain spatial and temporal locality and why they matter for performance.', type: 'computer_architecture', difficulty: 'medium', topic: 10, answer: 'Temporal locality: recently accessed data is likely to be accessed again soon (caches keep it hot). Spatial locality: data near a recently accessed address is likely to be accessed soon too (caches fetch whole lines, prefetchers extrapolate sequential patterns). Data structures and access patterns that respect both (e.g. iterating arrays sequentially instead of via scattered pointers) run dramatically faster due to cache hit rates alone.' },
  { title: 'SIMD and data-parallel code', prompt: 'What is SIMD, and what code patterns prevent a compiler from auto-vectorizing a loop?', type: 'computer_architecture', difficulty: 'hard', topic: 10, answer: 'SIMD (single instruction, multiple data) lets one CPU instruction operate on several data elements at once (e.g. 4-8 floats in one register), giving significant throughput for data-parallel numeric loops. Auto-vectorization breaks down with loop-carried dependencies (each iteration depends on the previous), branches inside the loop body, or pointer aliasing the compiler can\'t prove is safe to reorder.' },
  { title: 'Virtual memory and TLB', prompt: 'What is a TLB, and why does a TLB miss matter for performance?', type: 'computer_architecture', difficulty: 'medium', topic: 10, answer: 'The TLB (translation lookaside buffer) caches recent virtual-to-physical address translations so most memory accesses skip the full page-table walk. A TLB miss requires walking multi-level page tables (several extra memory accesses) before the actual data access can proceed, which is why workloads touching many pages randomly (large working sets, poor locality) suffer disproportionately compared to workloads that stay within a small hot set of pages.' },
  { title: 'Bias-variance tradeoff', prompt: 'Explain the bias-variance tradeoff and how it shows up as underfitting versus overfitting.', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'High bias (an overly simple model) underfits: it can\'t capture real patterns, so both training and validation error are high. High variance (an overly complex model) overfits: it captures noise specific to the training set, so training error is low but validation error is high. Model selection is choosing complexity that minimizes total error, typically via cross-validation.' },
  { title: 'Precision, recall, and F1', prompt: 'When would you optimize for precision over recall, or vice versa?', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'Optimize for precision when false positives are costly (e.g. flagging legitimate transactions as fraud annoys real customers). Optimize for recall when false negatives are costly (e.g. missing an actual fraud case or a real disease). F1 (harmonic mean of precision and recall) is useful when both matter and classes are imbalanced, since it penalizes extreme tradeoffs in either direction.' },
  { title: 'Train/validation/test split purpose', prompt: 'Why do you need three separate data splits instead of just train and test?', type: 'machine_learning', difficulty: 'easy', topic: 11, answer: 'The validation set is used to tune hyperparameters and make model-selection decisions during development; if you tuned directly against the test set, you\'d be indirectly fitting to it, inflating its reported performance. The test set is held out entirely until the very end to give an unbiased estimate of real-world generalization.' },
  { title: 'Regularization intuition', prompt: 'Explain what L1 and L2 regularization do differently to model weights.', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'L2 (ridge) penalizes the sum of squared weights, shrinking all weights smoothly toward zero without necessarily eliminating any. L1 (lasso) penalizes the sum of absolute weights, which tends to drive some weights exactly to zero, effectively performing feature selection. Both combat overfitting by discouraging overly large weights that fit training noise.' },
  { title: 'Feature scaling necessity', prompt: 'Why do some ML algorithms require feature scaling while others don\'t?', type: 'machine_learning', difficulty: 'easy', topic: 11, answer: 'Distance-based and gradient-based algorithms (KNN, SVM, gradient descent for linear/logistic regression, neural networks) are sensitive to feature scale, since a feature with a much larger numeric range can dominate a distance metric or gradient update regardless of its actual predictive value. Tree-based models (decision trees, random forests, gradient-boosted trees) split on threshold comparisons per feature independently, so scaling doesn\'t affect their decisions.' },
  { title: 'Encapsulation vs information hiding', prompt: 'Distinguish encapsulation from information hiding, and give an example where you have one without the other.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'Encapsulation bundles data and behavior together into one unit (a class); information hiding restricts what of that unit is visible/accessible from outside. A class with all public fields is encapsulated (data+methods together) but doesn\'t hide information — callers can bypass invariants by mutating fields directly. Proper design usually wants both together.' },
  { title: 'Interface segregation in practice', prompt: 'What problem does the interface segregation principle solve, with a concrete example?', type: 'oop', difficulty: 'medium', topic: 5, answer: 'A single "fat" interface forces implementers to provide (or stub out) methods irrelevant to them — e.g. a Printer interface with scan()/fax()/print() forces a print-only device to implement fax() somehow. Splitting into smaller, role-specific interfaces (Printable, Scannable, Faxable) lets each implementer depend only on what it actually needs, reducing coupling and unnecessary breakage when an unrelated method changes.' },
  { title: 'Composition vs inheritance for code reuse', prompt: 'Give a concrete scenario where inheritance seems natural but composition is the better choice.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'Modeling a Duck that "IsA" FlyingBird breaks down once you add a RubberDuck (doesn\'t fly) or a Penguin (doesn\'t fly but is still a bird) — the inheritance hierarchy fights the domain\'s real variation. Composition (a Duck HasA optional FlightBehavior, WalkBehavior, etc., injected per instance) lets behavior vary independently of the type hierarchy, without forcing awkward overrides or exceptions.' },
  { title: 'Liskov substitution violations', prompt: 'Give a classic example of a Liskov substitution principle violation and why it causes bugs.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'A Square extending Rectangle that overrides setWidth()/setHeight() to keep both sides equal breaks LSP: code that expects a Rectangle and calls setWidth(5) then setHeight(10) expecting a 5x10 rectangle instead silently gets a 10x10 square, because the subtype changed the expected behavior of the base type\'s contract. Any code correct for the base type must remain correct when a subtype is substituted in.' },
  { title: 'JavaScript prototypal inheritance', prompt: 'Explain how JavaScript\'s prototype chain differs from classical (class-based) inheritance.', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'Objects delegate property/method lookups to a prototype object (accessible via `__proto__` / `Object.getPrototypeOf`) at runtime, rather than instances being stamped from a fixed class definition at compile time. `class` syntax in modern JS is sugar over this same prototype-chain mechanism, not a separate inheritance model — methods still live on `SomeClass.prototype`.' },
  { title: 'Debouncing vs throttling', prompt: 'Explain the difference between debouncing and throttling an event handler, with a use case for each.', type: 'javascript', difficulty: 'easy', topic: 1, answer: 'Debouncing delays execution until a pause in events (fires once, after activity stops) — good for search-as-you-type, waiting until the user pauses. Throttling limits execution to at most once per time window regardless of event frequency — good for scroll/resize handlers where you want periodic updates during continuous activity, not just at the end.' },
  { title: 'Promise.all vs Promise.allSettled', prompt: 'When would you use Promise.allSettled instead of Promise.all?', type: 'javascript', difficulty: 'easy', topic: 1, answer: 'Promise.all rejects immediately if any promise rejects, discarding the results of the others. Promise.allSettled always resolves once every promise has settled, giving you the status and value/reason of each — useful when you want partial results (e.g. "fetch these 5 independent resources, show whichever succeeded") rather than an all-or-nothing outcome.' },
  { title: 'Event loop microtasks vs macrotasks', prompt: 'Why does a Promise callback run before a setTimeout(fn, 0) callback, even if the promise resolves later in the code?', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'Promise callbacks are queued as microtasks, and the event loop drains the entire microtask queue before processing the next macrotask (timers, I/O callbacks, etc.), even a 0ms timeout. So all pending microtasks — including ones queued while draining the microtask queue itself — run before control returns to the macrotask queue.' },
  { title: 'Structural typing in TypeScript', prompt: 'Explain structural (duck) typing in TypeScript and how it differs from nominal typing.', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'TypeScript compares types by their shape (which properties/methods exist and their types), not by an explicit declared relationship — two unrelated interfaces with identical members are interchangeable. Nominal typing (as in languages like Java or C#, and TS\'s own `private`/branded-type workarounds) requires an explicit declared inheritance/implementation relationship even if the shapes match.' },
  { title: 'Generics constraints', prompt: 'Why would you constrain a generic type parameter with `extends`, and what does it let you do that an unconstrained generic doesn\'t?', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'An unconstrained `<T>` gives the compiler no information about T\'s shape, so you can\'t safely access any property on a value of type T. `<T extends { id: string }>` tells the compiler every T has at least an `id: string`, so code inside the generic function can safely read `.id` while still accepting any type that satisfies that shape.' },
  { title: 'Discriminated unions for exhaustiveness', prompt: 'How does TypeScript\'s exhaustiveness checking (via `never`) help catch bugs when adding a new case to a discriminated union?', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'A `switch` over a discriminated union\'s tag, with a `default` branch that assigns the remaining value to a variable typed `never`, causes a compile error if a new union member is added but not handled — since the unhandled member is no longer assignable to `never`. This turns "did I handle every case?" from a runtime bug into a compile-time guarantee as the union evolves.' },
  { title: 'Express middleware ordering', prompt: 'Why does the order middleware is registered in an Express (or similar) app matter?', type: 'nodejs', difficulty: 'easy', topic: 0, answer: 'Middleware runs in registration order, each deciding whether to call `next()` to continue the chain or end the response itself. Auth checks must run before route handlers that need the authenticated user; error handlers must be registered last so they can catch errors from everything before them; body-parsing middleware must run before handlers that read `req.body`.' },
  { title: 'Node.js worker threads vs cluster', prompt: 'When would you reach for worker_threads versus the cluster module in Node.js?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'worker_threads share memory (via SharedArrayBuffer) and suit CPU-bound work you want to offload from the main event loop without spinning up separate OS processes — e.g. image processing, heavy computation. cluster forks separate OS processes, each with its own event loop and memory, and suits scaling I/O-bound HTTP handling across CPU cores (each process independently handles connections, load-balanced by the master).' },
  { title: 'Streaming large file uploads', prompt: 'Why would you stream a large file upload instead of buffering it entirely in memory first?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'Buffering an entire large upload in memory before processing scales memory usage linearly with concurrent uploads and file size, risking OOM under load. Streaming processes the data in chunks as it arrives (e.g. piping directly to disk, cloud storage, or a hashing/validation step), keeping memory usage roughly constant regardless of file size or concurrency.' },
  { title: 'Idempotency keys in practice', prompt: 'Where does the idempotency key live and get checked in a typical request lifecycle, and what should happen on a key collision with a different payload?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'The client generates the key and sends it as a header; the server looks it up in a store (often the same transaction as the operation) before processing. If the key already exists with a matching payload, return the stored result without re-executing side effects. If it exists with a *different* payload, reject the request (409) — reusing a key for a different operation is a client bug, not something to silently accept.' },
  { title: 'Circuit breaker pattern', prompt: 'Explain the circuit breaker pattern and its three states.', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Closed: requests flow normally, failures are counted. Open: after enough failures, the breaker trips and requests fail fast (without hitting the failing dependency) for a cooldown period, protecting both the caller and the struggling dependency from further load. Half-open: after cooldown, a limited number of test requests are let through; success transitions back to closed, failure returns to open.' },
  { title: 'Backpressure in a request pipeline', prompt: 'What is backpressure, and what happens to a service that ignores it under load?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Backpressure is a mechanism for a slower downstream consumer to signal an upstream producer to slow down (rather than silently buffering unboundedly). A service that ignores backpressure under load keeps accepting/queuing work faster than it can process, growing memory usage and latency until it OOMs or falls so far behind that responses become useless (client has already timed out).' },
  { title: 'Move semantics in C++', prompt: 'Explain move semantics in C++ and what problem std::move solves.', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'A move constructor/assignment transfers ownership of a resource (e.g. a heap buffer) from a temporary or explicitly-moved-from object instead of deep-copying it, leaving the source in a valid-but-unspecified (typically empty) state. `std::move` doesn\'t move anything itself — it\'s a cast that tells the compiler "treat this lvalue as an rvalue," enabling the move overload to be selected instead of the copy overload.' },
  { title: 'Smart pointers and ownership', prompt: 'When would you choose unique_ptr over shared_ptr, and what does shared_ptr\'s overhead come from?', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'unique_ptr expresses single, exclusive ownership with zero runtime overhead beyond a raw pointer — prefer it by default. shared_ptr allows multiple owners via reference counting, but that counting requires an atomic increment/decrement on copy/destruction (thread-safety overhead) plus a separate control-block allocation, so it should be reserved for genuinely shared-ownership scenarios, not used reflexively.' },

  // MOM-053: CS Fundamentals batch 2 (toward the plan's 150-item Gate-3 target).
  { title: 'Page replacement algorithms', prompt: 'Compare LRU and CLOCK page replacement, and explain why true LRU is rarely implemented in hardware.', type: 'os', difficulty: 'medium', topic: 3, answer: 'LRU evicts the least-recently-used page, giving good hit rates but requiring exact recency tracking (expensive per-access bookkeeping in hardware). CLOCK approximates LRU cheaply with a single reference bit per page and a circular pointer: on eviction, sweep pages clearing reference bits until one with a clear bit is found (never referenced since the last sweep), evicting that one. Most real OS/hardware use CLOCK-family approximations, not exact LRU.' },
  { title: 'Mutex vs spinlock', prompt: 'When would a spinlock be preferable to a mutex, despite busy-waiting seeming wasteful?', type: 'os', difficulty: 'medium', topic: 3, answer: 'A spinlock avoids the cost of a context switch (parking and later rescheduling a thread), which can exceed the lock hold time for very short critical sections, especially on multi-core systems where the lock is expected to be released quickly by another core. A mutex is better for longer or uncertain hold times, since busy-waiting during a long wait wastes CPU that could do useful work.' },
  { title: 'Inodes and hard vs symbolic links', prompt: 'Explain what an inode is and how hard links differ from symbolic links.', type: 'os', difficulty: 'easy', topic: 3, answer: 'An inode stores a file\'s metadata and pointers to its data blocks, separate from any particular filename. A hard link is another directory entry pointing at the same inode (the file has no single "original" — all hard links are equal, and the data persists until the last link is removed). A symbolic link is a separate small file containing a path string, which breaks if the target is moved or deleted.' },
  { title: 'Signal handling basics', prompt: 'Why is it dangerous to call most library functions (e.g. malloc) inside a signal handler?', type: 'os', difficulty: 'medium', topic: 3, answer: 'A signal can interrupt the program at an arbitrary point, including in the middle of another call to that same function (e.g. malloc holding an internal lock or mid-mutation of its internal structures) — re-entering it from the handler can deadlock or corrupt state. Signal handlers should stick to a small set of async-signal-safe functions, typically just setting a flag or writing to a pipe, and defer real work to the main program flow.' },
  { title: 'Load balancing algorithms', prompt: 'Compare round-robin, least-connections, and consistent-hashing load balancing strategies.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Round-robin distributes requests evenly in sequence, simple but ignores backend load/capacity differences. Least-connections routes to whichever backend currently has the fewest active connections, adapting to uneven request costs. Consistent hashing routes based on a hash of the request key (e.g. client ID), keeping the same client mostly pinned to the same backend — valuable for cache locality — while minimizing redistribution when backends are added/removed.' },
  { title: 'WebSockets vs long polling', prompt: 'When would you choose WebSockets over HTTP long polling for real-time updates?', type: 'networking', difficulty: 'medium', topic: 4, answer: 'WebSockets keep one persistent, full-duplex connection open, avoiding the overhead of repeated HTTP handshakes and headers that long polling incurs on every round trip. Long polling is simpler to deploy (works through more restrictive proxies/firewalls, no special protocol upgrade) and is often good enough for lower-frequency updates; WebSockets are worth the added complexity for high-frequency, low-latency, bidirectional needs (chat, live collaboration, gaming).' },
  { title: 'IPv4 exhaustion and NAT', prompt: 'Explain how NAT lets many devices share one public IPv4 address, and one limitation it introduces.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'NAT rewrites the source IP/port of outgoing packets to the router\'s public IP plus a unique port, tracking the mapping so return traffic can be routed back to the right internal device; this lets many private addresses share one public address. Limitation: an external host can\'t initiate a connection to a device behind NAT without extra mechanisms (port forwarding, STUN/TURN, UPnP), since there\'s no existing mapping for unsolicited inbound traffic.' },
  { title: 'TCP congestion control basics', prompt: 'Explain what TCP congestion control is trying to achieve and how slow start works.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Congestion control estimates available network capacity to avoid overwhelming the path with more data than it can handle, which would cause dropped packets and retransmission storms. Slow start begins with a small congestion window and roughly doubles it each round trip (exponential growth) until a loss is detected or a threshold is reached, at which point growth becomes more conservative (e.g. linear, in congestion avoidance).' },
  { title: 'ACID vs BASE', prompt: 'Contrast ACID and BASE consistency models, and when you would accept BASE.', type: 'database', difficulty: 'medium', topic: 2, answer: 'ACID (atomicity, consistency, isolation, durability) guarantees strict, immediate consistency after a committed transaction — the traditional relational-database model. BASE (basically available, soft state, eventual consistency) trades strict consistency for availability and partition tolerance, accepting that replicas may briefly disagree. BASE fits systems where availability under partition matters more than every reader seeing the absolute latest write immediately (e.g. a social feed\'s like count).' },
  { title: 'Database sharding strategies', prompt: 'Compare range-based and hash-based sharding, and a failure mode of each.', type: 'database', difficulty: 'medium', topic: 2, answer: 'Range-based sharding (e.g. by user ID range) keeps related data physically close and supports efficient range queries, but can create hot shards if writes cluster in one range (e.g. sequential IDs all landing on the newest shard). Hash-based sharding distributes load evenly but scatters range queries across many shards and complicates resharding, since a hash function change reshuffles nearly everything (consistent hashing mitigates this).' },
  { title: 'Connection pooling rationale', prompt: 'Why do applications use a database connection pool instead of opening a new connection per request?', type: 'database', difficulty: 'easy', topic: 2, answer: 'Establishing a new database connection involves a TCP handshake, authentication, and often TLS negotiation — expensive relative to a typical query. A pool keeps a set of already-established connections ready to reuse, and also caps total concurrent connections to the database so a traffic spike can\'t exhaust the database\'s own connection limit.' },
  { title: 'Full-text search indexing', prompt: 'How does an inverted index make full-text search fast, and what does it cost you?', type: 'database', difficulty: 'medium', topic: 2, answer: 'An inverted index maps each distinct term to the list of documents containing it, so a query for a term is a direct lookup instead of scanning every document\'s text. The cost is index maintenance overhead on writes (every insert/update must update the affected terms\' postings lists) and additional storage for the index itself, plus staleness if updates aren\'t indexed synchronously.' },
  { title: 'Thread-local storage', prompt: 'What problem does thread-local storage solve, with an example?', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'Thread-local storage gives each thread its own independent copy of a variable, avoiding the need for synchronization when the value is inherently per-thread (e.g. a per-thread random number generator seed, or a per-thread request context in a web server) rather than genuinely shared state. Each thread reads/writes its own copy with no contention or locking needed.' },
  { title: 'Futures and promises', prompt: 'Explain what a future/promise represents and how it differs from a plain callback.', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'A future/promise is a first-class value representing a computation that will complete later, which can be passed around, composed (chained, combined with others via combinators like all/race), and queried for completion — unlike a bare callback, which is just a function reference with no independent identity or composability. This makes error handling and combining multiple async operations far more structured.' },
  { title: 'Actor model concurrency', prompt: 'Explain the actor model and how it avoids shared-memory data races by design.', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'In the actor model, each actor owns its own private state and communicates with other actors only via asynchronous messages, processed one at a time by that actor. Since no actor ever directly touches another\'s memory, there\'s no shared mutable state to race on — concurrency safety comes from the messaging discipline, not locks.' },
  { title: 'Spinlock vs mutex under contention', prompt: 'What happens to a spinlock\'s CPU usage under high contention, and why is that a problem on a single-core system?', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'Under high contention, many threads busy-wait (spin) simultaneously, burning CPU cycles without making progress, and the actual lock holder may get preempted while other spinning threads waste time waiting for a lock that won\'t be released until the OS reschedules the holder — a scenario especially bad on a single core, where spinning threads directly steal the holder\'s CPU time instead of yielding it back sooner via a blocking wait.' },
  { title: 'Pipeline hazards', prompt: 'What is a data hazard in a CPU pipeline, and how does forwarding (bypassing) help?', type: 'computer_architecture', difficulty: 'hard', topic: 10, answer: 'A data hazard occurs when an instruction needs a result that a prior, still-in-flight instruction hasn\'t finished computing yet (e.g. instruction 2 reads a register instruction 1 hasn\'t written back). Forwarding routes the computed result directly from an earlier pipeline stage to the stage that needs it, bypassing the normal register-write-then-read path, avoiding a pipeline stall in many cases.' },
  { title: 'Out-of-order execution', prompt: 'Explain out-of-order execution and why it improves throughput without changing observable program behavior.', type: 'computer_architecture', difficulty: 'hard', topic: 10, answer: 'The CPU can execute instructions in an order different from program order when their true data dependencies allow it, filling pipeline stalls with independent, ready-to-run work instead of idling. A reorder buffer ensures results are still committed (retired) in original program order, so the program\'s externally-observable behavior matches sequential execution even though internal execution order was rearranged.' },
  { title: 'NUMA and memory locality', prompt: 'What is NUMA, and why can it cause surprising performance differences for the same workload on different cores?', type: 'computer_architecture', difficulty: 'medium', topic: 10, answer: 'NUMA (non-uniform memory access) systems have multiple CPU sockets, each with memory that\'s "local" (fast) to it and "remote" (slower, over an interconnect) relative to the other socket\'s memory. A thread scheduled on one socket accessing memory allocated near the other socket pays extra latency per access — NUMA-aware allocation and thread pinning keep data and the threads that use it on the same node.' },
  { title: 'Cache coherence (MESI)', prompt: 'Explain at a high level what a cache coherence protocol like MESI is solving.', type: 'computer_architecture', difficulty: 'hard', topic: 10, answer: 'When multiple CPU cores each cache their own copy of the same memory location, a coherence protocol ensures all cores see a consistent view — e.g. MESI tags each cache line as Modified, Exclusive, Shared, or Invalid, and cores broadcast/snoop bus traffic to invalidate or update other cores\' copies when one core writes to a line it doesn\'t exclusively own. Without this, cores could silently read stale cached values after another core\'s write.' },
  { title: 'Learning curves for diagnosing model fit', prompt: 'How do you use a learning curve (error vs. training set size) to tell whether a model is underfitting or overfitting?', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'If both training and validation error converge to a similarly high value as training set size grows, the model is underfitting (too simple to capture the pattern, more data won\'t help much). If training error stays low while validation error stays notably higher even with more data, the model is overfitting (memorizing training specifics) — more data, regularization, or a simpler model would help.' },
  { title: 'Gradient descent variants', prompt: 'Compare batch, stochastic, and mini-batch gradient descent.', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'Batch gradient descent computes the gradient over the entire dataset per update — accurate but slow and memory-heavy per step. Stochastic gradient descent updates per single example — fast, noisy updates that can escape shallow local minima but with high variance. Mini-batch (the common practical choice) averages gradients over a small batch, balancing update stability against compute/memory cost per step.' },
  { title: 'Word/data embeddings intuition', prompt: 'What problem do embeddings solve compared to one-hot encoding categorical data?', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'One-hot encoding treats every category as equally distant from every other, uses dimensionality equal to the category count, and captures no notion of similarity. Embeddings map categories (or words, items, etc.) to dense, lower-dimensional vectors learned so that similar things end up close together in vector space, both compressing the representation and encoding useful relationships the model can leverage.' },
  { title: 'Handling class imbalance', prompt: 'Name two techniques for handling severe class imbalance in a classification problem, and a risk of each.', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'Oversampling the minority class (or SMOTE-style synthetic examples) risks overfitting to a small set of repeated/near-duplicate examples. Class-weighted loss (penalizing minority-class errors more heavily) avoids duplicating data but can make training less stable if the weighting is too aggressive. Both should be paired with a metric other than raw accuracy (e.g. F1, precision-recall AUC), since accuracy alone is misleading under imbalance.' },
  { title: 'Single responsibility in practice', prompt: 'Give an example of a class that violates single responsibility, and how you\'d split it.', type: 'oop', difficulty: 'easy', topic: 5, answer: 'A `UserService` that both validates user input, saves to the database, and sends a welcome email has three reasons to change (validation rules, storage schema, email content/provider). Splitting into a validator, a repository, and a notification service — each with one axis of change — means a change to email templates can\'t accidentally break validation logic.' },
  { title: 'Abstract class vs interface', prompt: 'When would you use an abstract class instead of an interface, given both can define a contract?', type: 'oop', difficulty: 'medium', topic: 5, answer: 'An abstract class can provide shared implementation (default method bodies, shared fields/state) alongside the contract, useful when subclasses share meaningful common behavior. An interface (in languages without default methods, or by convention) is a pure contract with no shared state — better when unrelated classes need to satisfy the same shape without inheriting an implementation relationship (supports multiple interface implementation where multiple inheritance of classes isn\'t allowed).' },
  { title: 'Observer pattern use case', prompt: 'Describe a scenario where the observer pattern is a natural fit, and a downside to watch for.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'A UI element that needs to update whenever underlying data changes (e.g. a dashboard widget subscribing to a data store) is a natural observer pattern fit — the subject notifies all registered observers without needing to know their concrete types. Downside: unmanaged subscriptions can cause memory leaks (observers never unsubscribed) or surprising update-ordering/performance issues if there are many observers reacting to frequent changes.' },
  { title: 'Mixins/traits for shared behavior', prompt: 'What problem do mixins/traits solve that single inheritance can\'t?', type: 'oop', difficulty: 'medium', topic: 5, answer: 'Single inheritance only lets a class extend one parent, but a class often needs to share behavior from multiple unrelated sources (e.g. both "Serializable" and "Comparable" behavior). Mixins/traits let you compose in reusable chunks of behavior from multiple sources without needing a single linear inheritance chain to express all of them.' },
  { title: 'JavaScript "this" binding rules', prompt: 'Explain how `this` is determined in a regular function versus an arrow function.', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'A regular function\'s `this` is determined by how it\'s *called* (call-site binding: object.method() binds `this` to object, a bare call binds to undefined/global, and call/apply/bind can override it explicitly). An arrow function has no `this` of its own — it lexically captures `this` from its enclosing scope at definition time, which is why arrow functions are commonly used for callbacks that need to preserve the surrounding `this`.' },
  { title: 'Generators and iterators', prompt: 'Explain how a generator function\'s `yield` differs from a regular function\'s `return`.', type: 'javascript', difficulty: 'medium', topic: 1, answer: '`yield` pauses the generator\'s execution, returning a value to the caller while preserving all local state, and can be resumed later (continuing right after the yield) via `.next()`; a regular function\'s `return` ends execution entirely and discards its local state. This makes generators natural for lazily producing a sequence of values on demand, including infinite sequences.' },
  { title: 'CommonJS vs ES modules', prompt: 'What is a key structural difference between CommonJS require() and ES module import that affects tooling like tree-shaking?', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'CommonJS `require()` is a dynamic, runtime function call, so a bundler can\'t always statically determine what\'s imported without executing code. ES module `import`/`export` declarations are statically analyzable (fixed at parse time, not conditional/computed), letting bundlers determine unused exports and eliminate them (tree-shaking) — something far harder to do reliably with CommonJS.' },
  { title: 'Utility types in TypeScript', prompt: 'Explain what Partial<T> and Pick<T, K> do, and a scenario for each.', type: 'typescript', difficulty: 'easy', topic: 1, answer: 'Partial<T> makes every property of T optional — useful for a PATCH-style update payload where any subset of fields may be provided. Pick<T, K> constructs a new type with only the specified keys K from T — useful for a narrower API response type derived from a larger internal model without duplicating field definitions.' },
  { title: 'Type narrowing with type guards', prompt: 'Explain how a user-defined type guard function narrows a union type, and why the `is` return type annotation matters.', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'A function like `function isDog(a: Animal): a is Dog` lets TypeScript narrow the type of `a` inside any branch where the guard returned true, based purely on the `is` annotation (the runtime check inside the function is trusted by the compiler, not independently verified). Without the `is` annotation, the function would just return a plain boolean and the caller\'s type wouldn\'t narrow.' },
  { title: 'Enums vs union literal types', prompt: 'Why do many TypeScript style guides prefer string literal unions over enums?', type: 'typescript', difficulty: 'medium', topic: 1, answer: 'Numeric enums compile to extra runtime code (a lookup object) and their reverse-mapping behavior can be surprising; string literal unions (`type Status = "active" | "paused"`) are pure compile-time constructs with zero runtime footprint, structurally compatible with plain strings from APIs/JSON without an explicit cast, and easier to reason about in serialization boundaries.' },
  { title: 'Node.js EventEmitter pattern', prompt: 'Explain the EventEmitter pattern in Node.js and a risk if you forget to remove a listener.', type: 'nodejs', difficulty: 'easy', topic: 0, answer: 'EventEmitter lets an object register named events and multiple listeners subscribe/react to them asynchronously, decoupling the emitter from what happens in response. Forgetting to remove a listener when its owning object should be garbage-collected (e.g. subscribing per-request but never unsubscribing) causes a memory leak, since the emitter still holds a reference to the listener (and anything it closes over) indefinitely.' },
  { title: 'Node.js streams and backpressure', prompt: 'What does it mean for a writable stream to apply backpressure, and how should a piping producer respond?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'When a writable stream\'s internal buffer fills up faster than it can drain (e.g. writing to a slow disk or network), `.write()` returns false, signaling the producer to pause. A well-behaved producer stops pushing more data until the stream emits a `drain` event, at which point it\'s safe to resume — `.pipe()` handles this automatically, which is why it\'s preferred over manually reading and writing chunks.' },
  { title: 'child_process vs worker_threads', prompt: 'When would you reach for child_process instead of worker_threads for offloading work in Node.js?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'child_process spawns a fully separate OS process (its own memory space, can run a different executable/language entirely) — right for running external tools, isolating untrusted code, or needing true process-level isolation. worker_threads share the same process and can share memory via SharedArrayBuffer, with lower spawn overhead — better for offloading CPU-bound JS computation within the same application.' },
  { title: 'API versioning strategies', prompt: 'Compare URL-based versioning (/v1/, /v2/) with header-based versioning for a public API.', type: 'backend', difficulty: 'medium', topic: 0, answer: 'URL-based versioning is simple, visible, and cacheable per-version, but "leaks" version into every resource identifier and can encourage duplicating entire route trees. Header-based versioning (e.g. an Accept header with a version) keeps URLs stable and resource-identity clean, but is less discoverable/debuggable (not visible in a browser URL bar or simple curl) and complicates caching layers that don\'t vary cache keys by header.' },
  { title: 'Webhook delivery reliability', prompt: 'What should a webhook sender do to make delivery reliable given the receiver might be temporarily down?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Retry failed deliveries with exponential backoff and a bounded number of attempts, and include a unique event ID so the receiver can deduplicate if a retry arrives after a delayed original success. Sign the payload (e.g. HMAC) so the receiver can verify authenticity, and expose a way for the receiver to replay missed events (an event log/cursor) in case retries are exhausted.' },
  { title: 'Feature flags for safe rollout', prompt: 'How do feature flags reduce deployment risk compared to deploying directly to all users?', type: 'backend', difficulty: 'easy', topic: 0, answer: 'A feature flag decouples code deployment from feature exposure: new code ships dark (flag off), then gets enabled gradually (percentage rollout, specific user cohorts, internal-only) so a problem affects a small blast radius and can be reverted instantly by flipping the flag, without needing a new deployment or rollback.' },
  { title: 'Graceful shutdown handling', prompt: 'What should a server do when it receives a shutdown signal (e.g. SIGTERM) while requests are in flight?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Stop accepting new connections/requests immediately, but let in-flight requests finish (up to a bounded grace period) before actually exiting, closing database connections and other resources cleanly afterward. Skipping this and exiting immediately on signal receipt drops in-flight requests\' responses, which is especially disruptive during rolling deployments.' },
  { title: 'const correctness in C++', prompt: 'Why does marking a member function `const` matter, beyond documentation?', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'A `const` member function promises not to modify the object\'s observable state, which the compiler enforces (a non-const mutation inside it is a compile error) — this lets the function be called on const references/objects, which a non-const method cannot be. It\'s a real contract the type system checks, not just a comment.' },
  { title: 'Templates vs generics', prompt: 'How does C++ template instantiation differ from Java/C# generics in terms of when type-specific code is generated?', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'C++ templates are compile-time code generation: the compiler generates a fully separate, specialized version of the function/class for each concrete type used (monomorphization), enabling aggressive per-type optimization but increasing binary size. Java/C# generics are typically type-erased or use shared runtime representations, generating one version of the code that works across types via boxing/type tokens, trading some specialization for smaller code size.' },
  { title: 'Virtual destructors', prompt: 'Why must a base class have a virtual destructor if it will be deleted polymorphically through a base pointer?', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'Without a virtual destructor, `delete basePtr` (where basePtr actually points to a derived object) only calls the base class\'s destructor, skipping the derived class\'s cleanup — undefined behavior and resource leaks for anything the derived class owns. Marking the base destructor virtual ensures the correct most-derived destructor runs first, then each base destructor up the chain.' },
  { title: 'GPU memory hierarchy', prompt: 'Explain the difference between GPU global memory and shared memory, and why kernels are written to minimize global memory traffic.', type: 'hpc', difficulty: 'medium', topic: 3, answer: 'Global memory is large but has high latency relative to compute throughput; shared memory is a small, fast, on-chip scratchpad shared by threads within the same block. Well-written kernels load data from global memory into shared memory once, then have many threads reuse it from shared memory, amortizing the expensive global memory access across many operations instead of re-fetching per thread.', roleTags: ['hpc-gpu-engineer'] },
  { title: 'Roofline model intuition', prompt: 'What does the roofline model tell you about whether a kernel is compute-bound or memory-bound?', type: 'hpc', difficulty: 'hard', topic: 3, answer: 'The roofline model plots achievable performance against arithmetic intensity (operations per byte moved). A kernel with low arithmetic intensity is memory-bound — its performance is capped by memory bandwidth regardless of available compute — while one with high arithmetic intensity is compute-bound, capped by peak FLOPs. This tells you whether to optimize memory access patterns or the compute itself.', roleTags: ['hpc-gpu-engineer'] },
  { title: 'Monte Carlo simulation basics', prompt: 'Explain how Monte Carlo simulation estimates a quantity that\'s hard to compute analytically, and what determines its accuracy.', type: 'quant', difficulty: 'medium', topic: 2, answer: 'Monte Carlo simulation repeatedly samples random inputs according to their assumed distributions, runs the model on each sample, and aggregates results (e.g. averaging) to approximate the true expected value or distribution of an outcome. Accuracy improves with more samples (error typically shrinks proportional to 1/sqrt(N)), so there\'s a direct tradeoff between compute budget and estimate precision.', roleTags: ['quant-swe'] },
  { title: 'Value at Risk (VaR) tradeoffs', prompt: 'What does a 95% one-day VaR of $1M actually mean, and what does it fail to capture?', type: 'quant', difficulty: 'hard', topic: 2, answer: 'It means there\'s a 95% chance losses over the next day won\'t exceed $1M (equivalently, a 5% chance they will). It says nothing about *how bad* the tail beyond that 5% could be — two portfolios with identical VaR can have very different worst-case losses in that tail, which is why VaR is often paired with Conditional VaR / Expected Shortfall (the average loss given that the VaR threshold is breached).', roleTags: ['quant-swe'] },

  // MOM-054: CS Fundamentals batch 3 (closes the gap to the plan's 150-item target).
  { title: 'Sync vs async API design', prompt: 'When designing a backend endpoint that triggers a slow operation, when should you make it asynchronous (return immediately, notify later) instead of synchronous?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Go async when the operation duration exceeds a reasonable client timeout, is unpredictable (depends on external systems), or the client doesn\'t need the result immediately (e.g. report generation, bulk export). Return a job/task ID immediately, and let the client poll a status endpoint or receive a webhook/notification on completion, rather than holding a connection open for an unbounded time.' },
  { title: 'Pagination cursor stability', prompt: 'Why can offset-based pagination return duplicate or skipped items under concurrent writes, and how does cursor-based pagination avoid it?', type: 'backend', difficulty: 'medium', topic: 0, answer: 'Offset pagination re-derives "page N" by counting from the start each request; if rows are inserted/deleted between page loads, later pages shift, causing skipped or duplicated items. Cursor-based pagination anchors to a specific, stable value (e.g. the last-seen row\'s ID or timestamp) and asks for "everything after this cursor," which stays correct regardless of concurrent inserts/deletes elsewhere in the set.' },
  { title: 'Worker thread pool queue design', prompt: 'What should a Node.js background job queue do when a worker crashes mid-job?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'The job should not be silently lost: a robust queue only removes a job from the "in progress" state once the worker explicitly acknowledges completion, so a crashed worker\'s jobs become visible again after a visibility timeout and get picked up by another worker. Combined with idempotent job handlers, this makes at-least-once processing safe even under worker crashes.' },
  { title: 'process.nextTick vs setImmediate', prompt: 'In Node.js, how does process.nextTick differ from setImmediate in terms of when each runs?', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'process.nextTick callbacks run at the very end of the current operation, before the event loop continues to any phase — effectively before I/O events and before promise microtasks even, historically. setImmediate callbacks run in the "check" phase of the event loop, after I/O callbacks in the current iteration. In practice, nextTick queues drain more eagerly and can starve the event loop if used recursively without bound.' },
  { title: 'Array methods and mutation', prompt: 'Which common JavaScript array methods mutate the original array, and why does mixing mutating and non-mutating methods cause subtle bugs?', type: 'javascript', difficulty: 'easy', topic: 1, answer: 'push, pop, shift, unshift, splice, sort, and reverse mutate in place; map, filter, slice, and concat return new arrays. Mixing them carelessly (e.g. calling .sort() on an array you also hold a reference to elsewhere, assuming it\'s unchanged) causes bugs when other code observes the mutated original unexpectedly — especially with React/Redux-style state that assumes immutability for change detection.' },
  { title: 'WeakMap use cases', prompt: 'Why would you use a WeakMap instead of a Map to associate metadata with objects?', type: 'javascript', difficulty: 'medium', topic: 1, answer: 'A WeakMap holds its keys weakly — if the only remaining reference to a key object is inside the WeakMap, the garbage collector can still reclaim it, and the entry is automatically removed. A regular Map holds a strong reference to its keys, so associating metadata with many objects via a Map can leak memory indefinitely if those objects are otherwise no longer needed elsewhere in the program.' },
  { title: 'Conditional types in TypeScript', prompt: 'Explain what a conditional type like `T extends U ? X : Y` computes, with a simple example.', type: 'typescript', difficulty: 'hard', topic: 1, answer: 'A conditional type evaluates to X if T is assignable to U, otherwise Y — computed at the type level, similar to a ternary but operating on types instead of values. For example, `type IsString<T> = T extends string ? true : false` resolves `IsString<"a">` to `true` and `IsString<42>` to `false`, letting you build type-level logic (common in utility types like `Exclude`/`Extract`).' },
  { title: 'Readonly and immutability at the type level', prompt: 'What does the `readonly` modifier prevent, and what does it not prevent?', type: 'typescript', difficulty: 'easy', topic: 1, answer: '`readonly` prevents reassigning the property itself after initial assignment, caught at compile time. It does not deeply freeze the value — if the property holds an object or array, that object\'s own properties/elements can still be mutated (`readonly` is shallow), unless you also apply `Readonly<T>` recursively or use a true immutable data structure.' },
  { title: 'Covering indexes', prompt: 'What is a covering index, and why can it avoid a separate table lookup entirely?', type: 'database', difficulty: 'medium', topic: 2, answer: 'A covering index includes every column a query needs (in its filter, sort, and selected output), so the database can answer the query directly from the index itself without a second lookup into the main table (avoiding the extra "heap fetch" per matching row). This is a common targeted optimization for hot, narrow queries.' },
  { title: 'Optimistic locking with a version column', prompt: 'How does a version column implement optimistic locking, and what happens on a conflicting update?', type: 'database', difficulty: 'medium', topic: 2, answer: 'Each row carries a version number; an update includes a WHERE clause requiring the version to match what was read, and increments it on success. If another transaction updated the row first (version no longer matches), the update affects zero rows, and the application detects this and retries or surfaces a conflict to the user — no database-held lock is required while the user is "thinking."' },
  { title: 'Kernel vs user mode', prompt: 'Why does a system call require switching from user mode to kernel mode, and what does that switch cost?', type: 'os', difficulty: 'medium', topic: 3, answer: 'Privileged operations (direct hardware access, memory management, process control) are restricted to kernel mode for isolation and safety; user-mode code must trap into the kernel (via a system call instruction) to request them, since the CPU itself enforces the privilege boundary. The switch costs a save/restore of register state and a full mode transition, which is why syscall-heavy code (large numbers of small reads/writes) is often slower than batching them into fewer, larger calls.' },
  { title: 'Zombie and orphan processes', prompt: 'What is a zombie process, and how does it differ from an orphan process?', type: 'os', difficulty: 'medium', topic: 3, answer: 'A zombie process has finished executing but still has an entry in the process table because its parent hasn\'t yet called wait() to read its exit status — it\'s "dead" but not yet reaped. An orphan process is one whose parent has terminated first; it gets re-parented (typically to an init/reaper process) which will eventually reap it, so orphans don\'t linger as zombies indefinitely the way an unreaped child of a still-running parent can.' },
  { title: 'HTTP caching headers', prompt: 'Distinguish Cache-Control: max-age from ETag-based conditional requests.', type: 'networking', difficulty: 'medium', topic: 4, answer: 'max-age lets a client (or CDN) skip contacting the server entirely for a set duration, assuming the cached copy is still fresh — fastest, but risks serving stale data if the resource changed sooner. An ETag lets the client always ask the server "has this changed since I last saw ETag X?" (a conditional GET); the server responds 304 Not Modified (cheap, no body) if unchanged, or the full new resource if it has — always fresh, at the cost of one round trip.' },
  { title: 'Anycast routing basics', prompt: 'What is anycast, and why is it commonly used for DNS root servers and CDNs?', type: 'networking', difficulty: 'medium', topic: 4, answer: 'Anycast advertises the same IP address from multiple physical locations; network routing (BGP) sends each client\'s traffic to whichever advertised location is topologically closest, without the client needing to know multiple addresses exist. This gives automatic geographic load distribution and failover (if one location goes down, routing simply stops preferring it) with zero client-side configuration.' },
  { title: 'Template method pattern', prompt: 'Explain the template method pattern and how it differs from the strategy pattern.', type: 'oop', difficulty: 'medium', topic: 5, answer: 'Template method defines an algorithm\'s overall skeleton in a base class, with specific steps deferred to subclass overrides (inheritance-based customization of a fixed sequence). Strategy instead extracts the whole varying behavior into a separate, swappable object that\'s composed into the context at runtime (composition-based), which is more flexible since the behavior can be changed without subclassing or even at runtime.' },
  { title: 'Law of Demeter', prompt: 'Explain the Law of Demeter ("don\'t talk to strangers") with a chained-call example that violates it.', type: 'oop', difficulty: 'medium', topic: 5, answer: '`order.getCustomer().getAddress().getCity()` violates the Law of Demeter — it reaches through three layers of objects, coupling the caller tightly to the internal structure of Customer and Address. A method should generally only call methods on itself, its direct fields, its parameters, or objects it creates — here, `order.getCustomerCity()` would encapsulate the traversal so callers don\'t depend on the internal object graph shape.' },
  { title: 'RAII outside C++', prompt: 'RAII is often described as a C++ idiom, but what\'s the equivalent concept in Python or Java, and why is it not identical?', type: 'cpp', difficulty: 'medium', topic: 5, answer: 'Python\'s `with` statement (context managers) and Java\'s try-with-resources both tie resource cleanup to a scope, similarly to RAII — but they require explicit syntax at the *call site* (you must remember to write `with`/try-with-resources), whereas C++ RAII cleanup happens automatically via the destructor whenever any object goes out of scope, with no special call-site syntax needed, including on exception unwinding through arbitrary call depth.' },
  { title: 'Undefined behavior in C++', prompt: 'Give an example of undefined behavior in C++ and explain why compilers are allowed to assume it never happens.', type: 'cpp', difficulty: 'hard', topic: 5, answer: 'Signed integer overflow is undefined behavior in C++ — the compiler is permitted to assume it never occurs, and can optimize accordingly (e.g. assuming `x + 1 > x` is always true and eliminating a bounds check that depended on it). This is why a program that "happens to work" with UB present can break silently after a compiler upgrade or optimization-level change — there was never a guaranteed behavior to begin with.' },
  { title: 'Amdahl\'s Law', prompt: 'Explain Amdahl\'s Law and why adding more cores gives diminishing returns for a partially-parallel program.', type: 'hpc', difficulty: 'hard', topic: 3, answer: 'If a fraction P of a program\'s work is parallelizable and (1-P) is inherently serial, the maximum possible speedup with infinite processors is bounded by 1/(1-P) — the serial portion becomes the dominant cost no matter how much you parallelize the rest. This is why optimizing (or removing) serial bottlenecks often matters more than adding raw core count once a reasonable degree of parallelism is already achieved.', roleTags: ['hpc-gpu-engineer'] },
  { title: 'Lock-free vs wait-free', prompt: 'Distinguish lock-free from wait-free concurrent algorithms.', type: 'concurrency', difficulty: 'hard', topic: 9, answer: 'Lock-free guarantees that *some* thread makes progress in a bounded number of steps system-wide (no thread can block all others forever), but an individual thread could theoretically retry indefinitely if repeatedly preempted by others succeeding first. Wait-free is the stronger guarantee that *every* thread completes its operation in a bounded number of steps regardless of what other threads do — much harder to achieve and rarer in practice.' },
  { title: 'Producer-consumer with bounded queue', prompt: 'What can go wrong with a producer-consumer setup using an unbounded queue under sustained load, and how does bounding it help?', type: 'concurrency', difficulty: 'medium', topic: 9, answer: 'If producers are faster than consumers and the queue is unbounded, memory grows without limit as unconsumed items pile up, eventually exhausting memory. A bounded queue applies backpressure: once full, producers block (or get rejected) until consumers make room, naturally throttling the producer to the consumer\'s actual processing rate instead of hiding the mismatch behind ever-growing memory.' },
  { title: 'Cross-validation for small datasets', prompt: 'Why is k-fold cross-validation preferred over a single train/test split when data is limited?', type: 'machine_learning', difficulty: 'medium', topic: 11, answer: 'With limited data, a single split gives one noisy estimate of generalization performance highly dependent on which examples happened to land in the test set. K-fold cross-validation rotates which subset is held out across k folds and averages the results, using nearly all data for both training and evaluation across the folds, giving a more stable and reliable performance estimate.' },

  // MOM-045: DSA starter batch. Per D-008/ADR-0004, `prompt` and `answer` are
  // original notes written for this app, not the source problem's statement or
  // official editorial — read the actual problem at `sourceUrl` first, then use
  // these as pattern guidance while practicing. This is a starter batch, not the
  // full Gate-3 target of 150 items (see BACKLOG.md Track G for the remaining batches).
  { title: 'Two Sum', prompt: 'Solve "Two Sum" (read the full problem at the source link, LeetCode #1). Implement your solution, then explain why your approach hits the target time complexity.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/two-sum/', answer: 'Hash-map complement lookup: for each value, check whether target-minus-value has already been seen before inserting the current value. One pass, O(n) time, O(n) space. Watch for duplicate values reusing the same index and confirm the problem wants indices, not values.', patternTags: ['two_pointers'] },
  { title: 'Valid Parentheses', prompt: 'Solve "Valid Parentheses" (LeetCode #20). Implement your solution, then explain your invariant for why the stack approach is correct.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/valid-parentheses/', answer: 'Push opening brackets onto a stack; on a closing bracket, pop and check it matches the expected opener. Invalid if the stack is empty when popping, or non-empty at the end. O(n) time, O(n) space. This is the canonical entry point for monotonic-stack-style matching problems.', patternTags: ['monotonic_stack'] },
  { title: 'Merge Two Sorted Lists', prompt: 'Solve "Merge Two Sorted Lists" (LeetCode #21). Implement iteratively, then discuss the recursive alternative and its stack-depth tradeoff.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/merge-two-sorted-lists/', answer: 'Use a dummy head and a tail pointer; repeatedly attach the smaller current node from either list and advance that list. Append the remaining tail of whichever list is non-empty. O(n+m) time, O(1) extra space iteratively; the recursive version is O(n+m) call-stack space.', patternTags: ['two_pointers'] },
  { title: 'Best Time to Buy and Sell Stock', prompt: 'Solve "Best Time to Buy and Sell Stock" (LeetCode #121). Implement your one-pass solution and explain what invariant you track.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/best-time-to-buy-and-sell-stock/', answer: 'Track the minimum price seen so far and the best profit so far in one left-to-right pass; at each price, profit = price - minSoFar. O(n) time, O(1) space. This is the simplest member of the "track a running extreme while scanning" family that generalizes to Kadane-style problems.', patternTags: ['sliding_window'] },
  { title: 'Reverse Linked List', prompt: 'Solve "Reverse Linked List" (LeetCode #206). Implement both an iterative and a recursive version.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/reverse-linked-list/', answer: 'Iteratively, walk the list keeping prev/curr/next pointers and relink curr.next = prev each step. Recursively, reverse the rest of the list first, then fix up the current node\'s neighbor pointers on the way back up. O(n) time; O(1) space iteratively, O(n) call stack recursively. Foundational for many linked-list-reversal variants (reverse in groups of k, reverse between positions).', patternTags: ['linked_list_reversal'] },
  { title: 'Linked List Cycle', prompt: 'Solve "Linked List Cycle" (LeetCode #141). Implement Floyd\'s cycle detection and explain why the pointers must meet if a cycle exists.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/linked-list-cycle/', answer: 'Advance a slow pointer one step and a fast pointer two steps; if they ever meet, there is a cycle. If a cycle exists, once the slow pointer enters it, the fast pointer closes the gap between them by one node per step, so they must eventually coincide. O(n) time, O(1) space.', patternTags: ['fast_slow_pointers'] },
  { title: 'Longest Substring Without Repeating Characters', prompt: 'Solve "Longest Substring Without Repeating Characters" (LeetCode #3). Implement the sliding-window solution and explain how you shrink the window.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/longest-substring-without-repeating-characters/', answer: 'Maintain a window [left, right] and a map of last-seen index per character. On seeing a repeat inside the window, jump left to one past its previous occurrence (never move left backward). Track the max window length seen. O(n) time, O(min(n, charset)) space.', patternTags: ['sliding_window'] },
  { title: '3Sum', prompt: 'Solve "3Sum" (LeetCode #15). Implement the sort-plus-two-pointers approach and explain how you avoid duplicate triplets.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/3sum/', answer: 'Sort the array; fix each index i as the first element, then use two pointers moving inward over the remaining sorted suffix to find pairs summing to -nums[i]. Skip over duplicate values for i, and after finding a match, skip duplicates for both inner pointers before continuing. O(n^2) time, O(1) extra space beyond sorting.', patternTags: ['two_pointers'] },
  { title: 'Merge Intervals', prompt: 'Solve "Merge Intervals" (LeetCode #56). Implement your solution and explain why sorting first is necessary.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/merge-intervals/', answer: 'Sort intervals by start time, then scan once, merging the current interval into the last kept interval whenever its start is <= the last interval\'s end (extend the end if needed), otherwise appending it as a new interval. Sorting guarantees any overlap with earlier intervals is detected against the most recently merged one. O(n log n) time, O(n) space.', patternTags: ['merge_intervals'] },
  { title: 'Binary Tree Level Order Traversal', prompt: 'Solve "Binary Tree Level Order Traversal" (LeetCode #102). Implement a BFS solution that groups nodes by level.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/binary-tree-level-order-traversal/', answer: 'BFS with a queue, but capture the queue\'s size at the start of each iteration to know exactly how many nodes belong to the current level before enqueuing their children. O(n) time, O(n) space (widest level plus output).', patternTags: ['tree_bfs'] },
  { title: 'Course Schedule', prompt: 'Solve "Course Schedule" (LeetCode #207). Implement cycle detection over the prerequisite graph and explain which graph technique you used.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/course-schedule/', answer: 'Build a directed graph from prerequisites and run Kahn\'s algorithm: repeatedly remove zero-indegree nodes, decrementing neighbors\' indegree. If all nodes are eventually removed, there is no cycle and the schedule is possible; otherwise a cycle exists among the remaining nodes. O(V+E) time and space. Equivalent to topological sort existing iff the graph is a DAG.', patternTags: ['topological_sort', 'graph_traversal'] },
  { title: 'Number of Islands', prompt: 'Solve "Number of Islands" (LeetCode #200). Implement a grid-traversal solution and explain your visited-tracking strategy.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/number-of-islands/', answer: 'Scan every cell; on an unvisited land cell, increment the island count and flood-fill (DFS or BFS) in the four cardinal directions, marking visited cells (in-place mutation or a visited set) so they are not recounted. O(rows*cols) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Coin Change', prompt: 'Solve "Coin Change" (LeetCode #322). Implement the bottom-up DP and explain your state definition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/coin-change/', answer: 'Let dp[amount] be the fewest coins to make that amount, dp[0]=0, dp[x]=infinity if unreachable. For each amount from 1 upward, try every coin <= amount and take min(dp[amount], dp[amount-coin]+1). Answer is dp[target] or -1 if it stayed infinite. O(amount * numCoins) time, O(amount) space.', patternTags: ['dynamic_programming'] },
  { title: 'Kth Largest Element in an Array', prompt: 'Solve "Kth Largest Element in an Array" (LeetCode #215). Implement a heap-based solution and discuss the quickselect alternative\'s complexity.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/kth-largest-element-in-an-array/', answer: 'Maintain a min-heap of size k over the stream of numbers; once the heap exceeds size k, pop the smallest. The heap\'s root is the kth largest at the end. O(n log k) time, O(k) space. Quickselect (partition-based) achieves expected O(n) time but O(n) worst case and mutates the array.', patternTags: ['heap_priority_queue'] },
  { title: 'Word Break', prompt: 'Solve "Word Break" (LeetCode #139). Implement the DP solution and explain your state transition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/word-break/', answer: 'Let dp[i] mean the prefix of length i can be segmented using dictionary words. dp[0]=true; for each i, dp[i] is true if there exists j<i with dp[j] true and s[j:i] in the dictionary (as a set for O(1) lookup). Answer is dp[n]. O(n^2) time (or better with word-length bounds), O(n) space.', patternTags: ['dynamic_programming'] },
  { title: 'Trapping Rain Water', prompt: 'Solve "Trapping Rain Water" (LeetCode #42). Implement the two-pointer solution and explain why tracking left/right maxima works without a second array.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/trapping-rain-water/', answer: 'Water trapped above a bar is bounded by the shorter of the tallest bar to its left and to its right. Move two pointers inward from both ends, always advancing the side with the smaller running max, because that side\'s trapped water is fully determined regardless of what the far side\'s max eventually becomes. O(n) time, O(1) space, avoiding the O(n) prefix/suffix-max arrays of the simpler DP approach.', patternTags: ['two_pointers'] },
  { title: 'Median of Two Sorted Arrays', prompt: 'Solve "Median of Two Sorted Arrays" (LeetCode #4). Implement the O(log(min(m,n))) binary-search partition solution.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/median-of-two-sorted-arrays/', answer: 'Binary search a partition index on the smaller array; the partition on the larger array is determined by the combined-left-half size. Adjust the smaller array\'s partition until maxLeft <= minRight on both sides, then the median is derivable from the four boundary elements (average of two middles for even total length, or the max-left for odd). O(log(min(m,n))) time, O(1) space. Get the even/odd and empty-partition edge cases right before optimizing.', patternTags: ['binary_search'] },

  // MOM-046: DSA ladder batch 2 (toward the 150-item Gate-3 target). Fills the
  // patterns batch 1 didn't reach (cyclic_sort, tree_dfs, union_find,
  // backtracking, greedy, prefix_sum, bit_manipulation, trie) and adds depth to
  // several already-seeded patterns. Same D-008 rule: original notes + link only.
  { title: 'Missing Number', prompt: 'Solve "Missing Number" (LeetCode #268). Implement the cyclic-sort/XOR approach and explain why it avoids extra space.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/missing-number/', answer: 'XOR every index and every value together; matching pairs cancel to zero, leaving the missing number (since XOR is commutative/associative and a^a=0). Alternatively, place each value at its own index via cyclic sort and scan for the first mismatch. O(n) time, O(1) space either way.', patternTags: ['cyclic_sort'] },
  { title: 'Find All Numbers Disappeared in an Array', prompt: 'Solve "Find All Numbers Disappeared in an Array" (LeetCode #448). Implement the in-place index-marking approach.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-all-numbers-disappeared-in-an-array/', answer: 'For each value v, negate the element at index v-1 (if not already negative) to mark "v is present". A second pass collects indices whose value is still positive — those indices+1 were never marked, i.e. missing. O(n) time, O(1) extra space (mutates input, restore if the array must stay unchanged).', patternTags: ['cyclic_sort'] },
  { title: 'Maximum Depth of Binary Tree', prompt: 'Solve "Maximum Depth of Binary Tree" (LeetCode #104). Implement both a recursive and an iterative (BFS) solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/maximum-depth-of-binary-tree/', answer: 'Recursively, depth(node) = 1 + max(depth(left), depth(right)), with depth(null) = 0. Iteratively, BFS level-by-level and count levels, or DFS with an explicit stack tracking depth per node. O(n) time, O(h) recursive stack space (h = height) or O(w) BFS queue space (w = max width).', patternTags: ['tree_dfs'] },
  { title: 'Path Sum', prompt: 'Solve "Path Sum" (LeetCode #112). Implement the root-to-leaf DFS and explain your base case for a leaf.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/path-sum/', answer: 'DFS from the root, subtracting the current node\'s value from the remaining target. A leaf node (no children) matches only if the remaining target equals its own value — an internal node with remaining==0 is not a match unless it is also a leaf. O(n) time, O(h) space.', patternTags: ['tree_dfs'] },
  { title: 'Diameter of Binary Tree', prompt: 'Solve "Diameter of Binary Tree" (LeetCode #543). Implement the single-pass solution and explain what you compute at each node.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/diameter-of-binary-tree/', answer: 'At each node, compute left-height and right-height via post-order DFS; the diameter through this node is left-height + right-height, tracked in a running max across all nodes, while the function itself returns 1 + max(left, right) height for the parent call. O(n) time, O(h) space — avoid the naive O(n^2) that recomputes height per node.', patternTags: ['tree_dfs'] },
  { title: 'Number of Provinces', prompt: 'Solve "Number of Provinces" (LeetCode #547). Implement a union-find solution and explain your union-by-rank/path-compression choice.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/number-of-provinces/', answer: 'Union every pair (i, j) where the adjacency matrix marks a connection; the answer is the number of distinct roots left after processing all unions. Path compression (flatten find()) plus union-by-rank/size keeps near-O(1) amortized operations. O(n^2 * alpha(n)) time for an n x n matrix, O(n) space.', patternTags: ['union_find'] },
  { title: 'Redundant Connection', prompt: 'Solve "Redundant Connection" (LeetCode #684). Implement union-find and explain how you detect the extra edge.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/redundant-connection/', answer: 'Process edges in order, union-ing their endpoints; the first edge whose two endpoints are already in the same component (find(a) == find(b) before the union) is the redundant one, since a tree with n nodes has exactly n-1 edges. O(n * alpha(n)) time, O(n) space.', patternTags: ['union_find'] },
  { title: 'Subsets', prompt: 'Solve "Subsets" (LeetCode #78). Implement the backtracking solution and explain your choose/explore/unchoose pattern.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/subsets/', answer: 'At each index, branch into "include nums[i]" and "exclude nums[i]", recursing forward and popping the choice on the way back (backtrack) so the same mutable path array can be reused across branches. 2^n subsets, O(2^n) time, O(n) recursion depth.', patternTags: ['backtracking'] },
  { title: 'Permutations', prompt: 'Solve "Permutations" (LeetCode #46). Implement the backtracking solution and explain how you track used elements.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/permutations/', answer: 'Maintain a used[] boolean array (or swap-in-place); at each recursion level, try every unused element, mark it used, recurse, then unmark (backtrack) before trying the next. O(n! * n) time, O(n) space beyond the output.', patternTags: ['backtracking'] },
  { title: 'Combination Sum', prompt: 'Solve "Combination Sum" (LeetCode #39). Implement the backtracking solution and explain how you allow reuse of the same element.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/combination-sum/', answer: 'Sort candidates, then DFS from each index allowing the *same* index to be reused on the next recursive call (not index+1) since elements can repeat; prune branches once the running sum exceeds the target, and advance past duplicate candidate values at the top level to avoid duplicate combinations. Exponential worst case, bounded by target/min(candidate).', patternTags: ['backtracking'] },
  { title: 'N-Queens', prompt: 'Solve "N-Queens" (LeetCode #51). Implement the backtracking solution and explain your column/diagonal conflict tracking.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/n-queens/', answer: 'Place queens row by row; track occupied columns and the two diagonal families (row-col and row+col) as sets/bitmasks so each placement check is O(1). Backtrack when no column/diagonal is free for the current row. O(n!) worst case in practice, much better with pruning; O(n) space for the tracking sets plus recursion depth.', patternTags: ['backtracking'] },
  { title: 'Jump Game', prompt: 'Solve "Jump Game" (LeetCode #55). Implement the greedy farthest-reach solution and explain why greedy is sufficient here.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/jump-game/', answer: 'Track the farthest index reachable so far while scanning left to right; if the current index ever exceeds that farthest reach, the end is unreachable. Greedy works because maximizing reach at every step never hurts future options (no benefit to "saving" a jump). O(n) time, O(1) space.', patternTags: ['greedy'] },
  { title: 'Gas Station', prompt: 'Solve "Gas Station" (LeetCode #134). Implement the single-pass greedy solution and explain the correctness argument.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/gas-station/', answer: 'If the total gas >= total cost, a valid start exists. Scan once tracking a running tank total; whenever it goes negative, the start candidate resets to the next station (every station between the old and new candidate could not have been a valid start either, since the deficit only compounds). O(n) time, O(1) space.', patternTags: ['greedy'] },
  { title: 'Task Scheduler', prompt: 'Solve "Task Scheduler" (LeetCode #621). Implement the greedy/math solution and explain your formula for the idle slots.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/task-scheduler/', answer: 'Count task frequencies; the most frequent task forces (maxFreq - 1) full cooldown blocks of size (n+1), plus one more slot for each task tied at maxFreq. The answer is max(total task count, that formula\'s slot count) since extra low-frequency tasks can fill idle gaps without changing the schedule length once there are enough of them. O(tasks) time, O(1) space (26-letter alphabet).', patternTags: ['greedy'] },
  { title: 'Subarray Sum Equals K', prompt: 'Solve "Subarray Sum Equals K" (LeetCode #560). Implement the prefix-sum + hash-map solution and explain the key insight.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/subarray-sum-equals-k/', answer: 'Track a running prefix sum and a hash map of {prefix sum -> count of times seen}. A subarray ending at the current index sums to k exactly when (runningSum - k) has been seen before; add that count to the answer, then record the current running sum. Seed the map with {0: 1} to count subarrays starting at index 0. O(n) time, O(n) space.', patternTags: ['prefix_sum'] },
  { title: 'Product of Array Except Self', prompt: 'Solve "Product of Array Except Self" (LeetCode #238). Implement the O(1)-extra-space (excluding output) prefix/suffix product solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/product-of-array-except-self/', answer: 'First pass: fill the output array with the running product of all elements to the left of each index. Second pass: scan right-to-left accumulating the running product of elements to the right, multiplying it into the existing output value at each index. No division needed, so it handles zeros correctly. O(n) time, O(1) extra space beyond the output array.', patternTags: ['prefix_sum'] },
  { title: 'Single Number', prompt: 'Solve "Single Number" (LeetCode #136). Implement the XOR solution and explain why it works.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/single-number/', answer: 'XOR every element together: pairs of equal values cancel to zero (a^a=0) and XOR is commutative/associative, so only the unpaired value survives. O(n) time, O(1) space, no extra data structure needed.', patternTags: ['bit_manipulation'] },
  { title: 'Number of 1 Bits', prompt: 'Solve "Number of 1 Bits" (LeetCode #191). Implement the Brian Kernighan\'s algorithm solution and explain what n & (n-1) does.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/number-of-1-bits/', answer: 'n & (n-1) clears the lowest set bit of n (since n-1 flips all bits below and including that lowest set bit). Repeating this and counting iterations until n becomes 0 gives the popcount directly, doing one iteration per set bit rather than per bit position. O(number of set bits) time, O(1) space.', patternTags: ['bit_manipulation'] },
  { title: 'Counting Bits', prompt: 'Solve "Counting Bits" (LeetCode #338). Implement the O(n) DP-over-bits solution and explain your recurrence.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/counting-bits/', answer: 'dp[i] = dp[i >> 1] + (i & 1): shifting i right by one drops the lowest bit, whose popcount you already computed, and you add back 1 if that dropped bit was a 1. Builds the whole answer array in one forward pass. O(n) time, O(n) space (output array).', patternTags: ['bit_manipulation'] },
  { title: 'Implement Trie (Prefix Tree)', prompt: 'Solve "Implement Trie (Prefix Tree)" (LeetCode #208). Implement insert/search/startsWith and explain your node structure.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/implement-trie-prefix-tree/', answer: 'Each node holds a fixed-size (or map-based) array of child pointers per character plus an isEndOfWord flag. Insert walks/creates nodes character by character and marks the last node as end-of-word; search walks the same path and requires isEndOfWord true at the end, while startsWith only requires the path to exist. O(L) time per operation (L = string length), O(total characters inserted) space.', patternTags: ['trie'] },
  { title: 'Design Add and Search Words Data Structure', prompt: 'Solve "Design Add and Search Words Data Structure" (LeetCode #211). Implement the trie + wildcard DFS solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/design-add-and-search-words-data-structure/', answer: 'Store words in a standard trie. On search, DFS through the trie matching literal characters directly; on a \'.\' wildcard, branch into every existing child at that level and recurse. Worst case (many dots) is O(26^L), but typical queries are much faster since most branches dead-end quickly.', patternTags: ['trie'] },
  { title: 'Container With Most Water', prompt: 'Solve "Container With Most Water" (LeetCode #11). Implement the two-pointer solution and explain why you always move the shorter side.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/container-with-most-water/', answer: 'Start pointers at both ends; area is limited by the shorter line, so moving the taller side inward can only shrink width without any chance of a taller limiting height, while moving the shorter side inward is the only move that could improve the limiting height. O(n) time, O(1) space.', patternTags: ['two_pointers'] },
  { title: 'Valid Palindrome', prompt: 'Solve "Valid Palindrome" (LeetCode #125). Implement the two-pointer solution and explain your character-filtering approach.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/valid-palindrome/', answer: 'Two pointers from both ends, skipping non-alphanumeric characters on each side before comparing lowercase values; mismatch means not a palindrome, pointers crossing means it is. O(n) time, O(1) space (no need to build a cleaned copy of the string).', patternTags: ['two_pointers'] },
  { title: 'Minimum Window Substring', prompt: 'Solve "Minimum Window Substring" (LeetCode #76). Implement the sliding-window + character-count solution and explain your shrink condition.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/minimum-window-substring/', answer: 'Expand the right edge, decrementing a "needed" counter whenever a required character\'s remaining count is still positive; once all required characters are satisfied, shrink the left edge as far as possible while still valid, recording the window size each time. O(n) time (each pointer moves forward at most n times), O(charset) space.', patternTags: ['sliding_window'] },
  { title: 'Longest Repeating Character Replacement', prompt: 'Solve "Longest Repeating Character Replacement" (LeetCode #424). Implement the sliding-window solution and explain your window-validity condition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/longest-repeating-character-replacement/', answer: 'Expand the window while tracking the count of the most frequent character inside it; the window is valid as long as (window length - count of most frequent char) <= k replacements allowed. When invalid, shrink from the left by one (the max-frequency count can be left stale — it only needs to be a correct upper bound, since the answer is monotonic non-decreasing). O(n) time, O(charset) space.', patternTags: ['sliding_window'] },
  { title: 'Climbing Stairs', prompt: 'Solve "Climbing Stairs" (LeetCode #70). Implement the O(1)-space DP solution and explain the Fibonacci connection.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/climbing-stairs/', answer: 'ways(n) = ways(n-1) + ways(n-2), since the last step taken is either a single step from n-1 or a double step from n-2 — identical recurrence to Fibonacci. Track only the last two values instead of a full array. O(n) time, O(1) space.', patternTags: ['dynamic_programming'] },
  { title: 'House Robber', prompt: 'Solve "House Robber" (LeetCode #198). Implement the O(1)-space DP solution and explain your state transition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/house-robber/', answer: 'At each house, the best result is max(skip this house -> carry forward the best-so-far, rob this house -> this house\'s value + best result two houses back). Track just the previous two running maxima instead of a full DP array. O(n) time, O(1) space.', patternTags: ['dynamic_programming'] },
  { title: 'Longest Increasing Subsequence', prompt: 'Solve "Longest Increasing Subsequence" (LeetCode #300). Implement the O(n log n) patience-sorting/binary-search solution and explain what the auxiliary array represents.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/longest-increasing-subsequence/', answer: 'Maintain an array `tails` where tails[i] is the smallest possible tail value of an increasing subsequence of length i+1 seen so far. For each new number, binary-search for where it belongs in `tails` and overwrite (or append); the final length of `tails` is the LIS length — note `tails` itself is not a valid subsequence, only its length is meaningful. O(n log n) time, O(n) space, versus the simpler O(n^2) DP.', patternTags: ['dynamic_programming'] },
  { title: 'Clone Graph', prompt: 'Solve "Clone Graph" (LeetCode #133). Implement the DFS + hash-map solution and explain how you avoid infinite loops on cycles.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/clone-graph/', answer: 'Maintain a map from original node to its clone; DFS (or BFS) from the start node, and before recursing into a neighbor, check the map — if the neighbor is already cloned (including the case of cycles pointing back to an ancestor), reuse that clone instead of recursing again. O(V+E) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Top K Frequent Elements', prompt: 'Solve "Top K Frequent Elements" (LeetCode #347). Implement the heap-based solution and explain the alternative bucket-sort approach\'s complexity.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/top-k-frequent-elements/', answer: 'Count frequencies with a hash map, then maintain a min-heap of size k over (frequency, value) pairs, popping the smallest whenever the heap exceeds k. O(n log k) time, O(n) space. Bucket sort (index = frequency, up to n buckets) achieves O(n) time by avoiding the heap entirely, trading it for O(n) auxiliary buckets.', patternTags: ['heap_priority_queue'] },
  { title: 'Merge k Sorted Lists', prompt: 'Solve "Merge k Sorted Lists" (LeetCode #23). Implement the min-heap solution and explain the divide-and-conquer alternative\'s complexity.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/merge-k-sorted-lists/', answer: 'Push the head of each list into a min-heap keyed by value; repeatedly pop the smallest, append it to the result, and push its successor (if any) back in. O(N log k) time (N = total nodes, k = number of lists), O(k) heap space. Pairwise divide-and-conquer merging achieves the same O(N log k) time without a heap, by merging lists two at a time in a binary-tree pattern.', patternTags: ['heap_priority_queue'] },
  { title: 'Search in Rotated Sorted Array', prompt: 'Solve "Search in Rotated Sorted Array" (LeetCode #33). Implement the modified binary search and explain how you determine which half is sorted.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/search-in-rotated-sorted-array/', answer: 'At each step, at least one half (left..mid or mid..right) is normally sorted; compare nums[left] to nums[mid] to determine which half is sorted, then check whether the target falls within that sorted half\'s range to decide which side to recurse into. O(log n) time, O(1) space.', patternTags: ['binary_search'] },
  { title: 'Daily Temperatures', prompt: 'Solve "Daily Temperatures" (LeetCode #739). Implement the monotonic-stack solution and explain what invariant the stack maintains.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/daily-temperatures/', answer: 'Maintain a stack of indices with strictly decreasing temperatures. For each new day, pop every stack index whose temperature is lower than today\'s, recording (today - popped index) as that day\'s answer, then push today\'s index. Each index is pushed and popped at most once. O(n) time, O(n) space.', patternTags: ['monotonic_stack'] },

  // MOM-047: DSA ladder batch 3 (toward the 150-item Gate-3 target). Adds a
  // second/third layer of depth to every pattern already introduced in batches 1-2
  // (MOM-045/046), since a real ladder needs multiple problems per pattern at
  // increasing difficulty, not just one. Same D-008 rule: original notes + link only.
  { title: 'Reverse Linked List II', prompt: 'Solve "Reverse Linked List II" (LeetCode #92). Implement the one-pass in-place reversal between positions left and right.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/reverse-linked-list-ii/', answer: 'Walk to the node just before `left` with a dummy head to handle left=1 cleanly. From there, repeatedly move the node right after the "before" pointer to the front of the reversed sub-segment (a "insert at head" trick), (right-left) times. O(n) time, O(1) space, single pass.', patternTags: ['linked_list_reversal'] },
  { title: 'Swap Nodes in Pairs', prompt: 'Solve "Swap Nodes in Pairs" (LeetCode #24). Implement the iterative pointer-relinking solution without just swapping values.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/swap-nodes-in-pairs/', answer: 'Keep a `prev` pointer before each pair; relink prev.next, first.next, and second.next so the pair swaps positions, then advance prev to the (now second) node of the pair. A dummy head simplifies swapping the first pair. O(n) time, O(1) space.', patternTags: ['linked_list_reversal'] },
  { title: 'Middle of the Linked List', prompt: 'Solve "Middle of the Linked List" (LeetCode #876). Implement the fast/slow pointer solution and explain why it lands on the correct middle for even-length lists.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/middle-of-the-linked-list/', answer: 'Advance slow by one node and fast by two; when fast reaches the end (or null), slow is at the middle. For even-length lists this naturally lands on the second of the two middle nodes, matching the problem\'s expected behavior. O(n) time, O(1) space, single pass.', patternTags: ['fast_slow_pointers'] },
  { title: 'Happy Number', prompt: 'Solve "Happy Number" (LeetCode #202). Implement the cycle-detection solution and explain why a non-happy number always cycles.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/happy-number/', answer: 'Treat "repeatedly sum of squared digits" as a function and detect a cycle with fast/slow pointers (or a seen-set) over its iterated values; the sequence is bounded (squared-digit-sum of any number below a threshold stays below it), so by pigeonhole it must eventually repeat a value if it never reaches 1. O(log n) per step, small bounded total work.', patternTags: ['fast_slow_pointers'] },
  { title: 'Insert Interval', prompt: 'Solve "Insert Interval" (LeetCode #57). Implement the single-pass solution and explain your three phases.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/insert-interval/', answer: 'Three phases in one pass: append all intervals ending before the new interval starts, merge all intervals that overlap the new interval (expanding its bounds), then append the merged interval and all remaining intervals. O(n) time, O(n) output space.', patternTags: ['merge_intervals'] },
  { title: 'Non-overlapping Intervals', prompt: 'Solve "Non-overlapping Intervals" (LeetCode #435). Implement the greedy-by-end-time solution and explain why sorting by end time (not start) is correct.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/non-overlapping-intervals/', answer: 'Sort by end time; greedily keep an interval if it starts at or after the last kept interval\'s end, otherwise count it as removed. Sorting by end time (not start) maximizes room for future intervals, since keeping the earliest-ending option is never worse. O(n log n) time, O(1) extra space beyond sorting.', patternTags: ['merge_intervals'] },
  { title: 'Binary Tree Right Side View', prompt: 'Solve "Binary Tree Right Side View" (LeetCode #199). Implement the BFS solution and explain how you pick the rightmost node per level.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/binary-tree-right-side-view/', answer: 'BFS level by level (tracking level size like in level-order traversal); the last node processed at each level is the one visible from the right side. A DFS variant (right child before left, recording the first node seen at each depth) works too. O(n) time, O(w) space (w = max width).', patternTags: ['tree_bfs'] },
  { title: 'Binary Tree Zigzag Level Order Traversal', prompt: 'Solve "Binary Tree Zigzag Level Order Traversal" (LeetCode #103). Implement the BFS solution with alternating direction per level.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/binary-tree-zigzag-level-order-traversal/', answer: 'Standard level-order BFS, but reverse the collected values for every other level (or push to the front/back of the level\'s output alternately). The traversal order and queue mechanics are unchanged — only the output ordering per level flips. O(n) time, O(w) space.', patternTags: ['tree_bfs'] },
  { title: 'Average of Levels in Binary Tree', prompt: 'Solve "Average of Levels in Binary Tree" (LeetCode #637). Implement the BFS level-sum solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/average-of-levels-in-binary-tree/', answer: 'BFS level by level, summing all node values at the current level and dividing by the level\'s node count before moving to the next level. O(n) time, O(w) space.', patternTags: ['tree_bfs'] },
  { title: 'Course Schedule II', prompt: 'Solve "Course Schedule II" (LeetCode #210). Implement Kahn\'s algorithm and explain how you produce a valid ordering, not just a yes/no answer.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/course-schedule-ii/', answer: 'Same as Course Schedule (Kahn\'s algorithm, repeatedly removing zero-indegree nodes) but append each removed node to an output list as you go; if the final list has fewer nodes than the course count, a cycle exists and no ordering is possible (return empty). O(V+E) time and space.', patternTags: ['topological_sort'] },
  { title: 'Minimum Height Trees', prompt: 'Solve "Minimum Height Trees" (LeetCode #310). Implement the leaf-trimming (topological-style) solution and explain why the last remaining node(s) are the answer.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/minimum-height-trees/', answer: 'Repeatedly peel off all current leaves (degree-1 nodes) layer by layer, like a topological/BFS trim from the outside in. The last 1-2 nodes remaining are the tree\'s "center" — the node(s) minimizing the maximum distance to any other node — since peeling layers is equivalent to shrinking the tree\'s diameter from both ends simultaneously. O(V) time and space.', patternTags: ['topological_sort', 'graph_traversal'] },
  { title: 'Next Greater Element I', prompt: 'Solve "Next Greater Element I" (LeetCode #496). Implement the monotonic-stack + hash-map solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/next-greater-element-i/', answer: 'Scan the full array once with a decreasing monotonic stack; whenever the current value exceeds the stack\'s top, pop it and record current value as its "next greater" in a hash map. After one pass, look up each query value in the map (default -1 if never resolved). O(n) time, O(n) space.', patternTags: ['monotonic_stack'] },
  { title: 'Asteroid Collision', prompt: 'Solve "Asteroid Collision" (LeetCode #735). Implement the stack simulation and explain your collision rules.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/asteroid-collision/', answer: 'Push right-moving (positive) asteroids onto a stack; a left-moving (negative) asteroid collides with the stack\'s top while it is positive and smaller in magnitude (pop and continue), destroys it and stops if equal magnitude, or is itself destroyed if the top is bigger. Only push the left-mover if the stack empties or its top is already negative. O(n) time, O(n) space.', patternTags: ['monotonic_stack'] },
  { title: 'Find Minimum in Rotated Sorted Array', prompt: 'Solve "Find Minimum in Rotated Sorted Array" (LeetCode #153). Implement the modified binary search and explain your comparison against the rightmost element.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-minimum-in-rotated-sorted-array/', answer: 'Compare nums[mid] to nums[right]: if nums[mid] > nums[right], the minimum is strictly to the right of mid (search right half); otherwise the minimum is at mid or to its left (search left half, inclusive of mid). Converges to the rotation point. O(log n) time, O(1) space.', patternTags: ['binary_search'] },
  { title: 'Koko Eating Bananas', prompt: 'Solve "Koko Eating Bananas" (LeetCode #875). Implement binary search on the answer and explain what makes the feasibility check monotonic.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/koko-eating-bananas/', answer: 'Binary search over possible eating speeds k (1..max pile); for a candidate k, a feasibility check computes total hours needed (sum of ceil(pile/k)) in O(piles) time. Feasibility is monotonic in k (higher speed never needs more hours), so binary search on the answer applies directly. O(piles * log(maxPile)) time, O(1) space.', patternTags: ['binary_search'] },
  { title: 'Search a 2D Matrix', prompt: 'Solve "Search a 2D Matrix" (LeetCode #74). Implement the single binary search over the matrix treated as a flattened sorted array.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/search-a-2d-matrix/', answer: 'Since each row\'s last value is less than the next row\'s first value, the whole matrix is equivalent to one sorted 1D array of length rows*cols; binary search over that virtual index and convert mid -> (mid / cols, mid % cols) to read the real cell. O(log(rows*cols)) time, O(1) space.', patternTags: ['binary_search'] },
  { title: 'Accounts Merge', prompt: 'Solve "Accounts Merge" (LeetCode #721). Implement the union-find-over-emails solution and explain how you group accounts by shared email.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/accounts-merge/', answer: 'Union every pair of emails that appear together in the same account; after processing all accounts, group emails by their root parent, then attach the matching account\'s name to each group and sort the emails for output. O(n * alpha(n) log n) time (sorting dominates), O(n) space.', patternTags: ['union_find'] },
  { title: 'Evaluate Division', prompt: 'Solve "Evaluate Division" (LeetCode #399). Implement the weighted union-find (or graph BFS) solution and explain how you track the ratio along unions.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/evaluate-division/', answer: 'Model each equation a/b=k as a weighted edge; weighted union-find stores, per node, a ratio to its parent, updated during union and path compression so any two nodes in the same component can resolve their ratio via root ratios. A plain graph+BFS/DFS multiplying edge weights along the path also works and is simpler to reason about first. O(q * alpha(n)) or O(q * (V+E)) depending on approach.', patternTags: ['union_find'] },
  { title: 'Number of Operations to Make Network Connected', prompt: 'Solve "Number of Operations to Make Network Connected" (LeetCode #1319). Implement the union-find solution and explain your feasibility check.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/number-of-operations-to-make-network-connected/', answer: 'If there are fewer cables than (n-1), it is impossible regardless of arrangement — return -1. Otherwise, union-find over all given connections; the number of extra cables needed equals (number of distinct components - 1), since each redundant cable within an already-connected component can be repurposed to join two separate components. O(edges * alpha(n)) time, O(n) space.', patternTags: ['union_find'] },
  { title: 'Range Sum Query - Immutable', prompt: 'Solve "Range Sum Query - Immutable" (LeetCode #303). Implement the prefix-sum precomputation and explain your O(1) query formula.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/range-sum-query-immutable/', answer: 'Precompute prefix[i] = sum of the first i elements in O(n) once; any range sum [l, r] is then prefix[r+1] - prefix[l] in O(1). Only worth it when many queries are expected against an immutable array — a single query wouldn\'t justify the precomputation.', patternTags: ['prefix_sum'] },
  { title: 'Continuous Subarray Sum', prompt: 'Solve "Continuous Subarray Sum" (LeetCode #523). Implement the prefix-sum-modulo-k + hash-map solution and explain the modular arithmetic insight.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/continuous-subarray-sum/', answer: 'Track running prefix sum mod k and a map of {remainder -> earliest index seen}. If the same remainder appears again at least 2 indices later, the subarray between those two indices sums to a multiple of k (since equal remainders mean the difference is divisible by k). Seed the map with {0: -1} to handle subarrays starting at index 0. O(n) time, O(min(n,k)) space.', patternTags: ['prefix_sum'] },
  { title: 'Subarray Sums Divisible by K', prompt: 'Solve "Subarray Sums Divisible by K" (LeetCode #974). Implement the prefix-sum-modulo-k + counting solution and explain how it generalizes Subarray Sum Equals K.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/subarray-sums-divisible-by-k/', answer: 'Same family as Subarray Sum Equals K, but counting by remainder instead of exact value: track a count map of {prefix sum mod k -> occurrences} (normalizing negative remainders into [0,k)); a subarray is divisible by k whenever its endpoints share the same remainder, so add the current remainder\'s existing count to the answer before incrementing it. O(n) time, O(k) space.', patternTags: ['prefix_sum'] },
  { title: 'Replace Words', prompt: 'Solve "Replace Words" (LeetCode #648). Implement the trie-based shortest-root-prefix lookup.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/replace-words/', answer: 'Insert all dictionary roots into a trie. For each word in the sentence, walk the trie character by character; the first isEndOfWord node hit along that walk is the shortest matching root (replace with it), otherwise leave the word unchanged. O(total root characters + total sentence characters) time.', patternTags: ['trie'] },
  { title: 'Longest Word in Dictionary', prompt: 'Solve "Longest Word in Dictionary" (LeetCode #720). Implement the trie solution and explain your "buildable one letter at a time" constraint.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/longest-word-in-dictionary/', answer: 'Insert all words into a trie, marking end-of-word nodes. A word only counts if every prefix of it (one character shorter each time) is also a complete word in the dictionary — check this by walking the trie and requiring isEndOfWord true at every intermediate node along the path, not just the final one. Track the longest (then lexicographically smallest) qualifying word. O(total characters) time.', patternTags: ['trie'] },
  { title: 'First Missing Positive', prompt: 'Solve "First Missing Positive" (LeetCode #41). Implement the O(n) time / O(1) space cyclic-sort placement solution.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/first-missing-positive/', answer: 'The answer is always in [1, n+1]. Cyclic-sort each value v (1<=v<=n) into index v-1 by repeated swapping; afterward, scan for the first index i where nums[i] != i+1 — that i+1 is the answer (or n+1 if all positions match). O(n) time (each element is swapped into place at most once), O(1) extra space.', patternTags: ['cyclic_sort'] },
  { title: 'Set Mismatch', prompt: 'Solve "Set Mismatch" (LeetCode #645). Implement the cyclic-sort or negative-marking solution and explain how you find both the duplicate and the missing number.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/set-mismatch/', answer: 'Cyclic-sort each value into its "home" index (value v at index v-1); a swap that would place a value where an equal value already sits reveals the duplicate immediately. After sorting, the one index whose value doesn\'t match its position (index+1) reveals both the duplicate (the value already there) and the missing number (index+1). O(n) time, O(1) space.', patternTags: ['cyclic_sort'] },
  { title: '3Sum Closest', prompt: 'Solve "3Sum Closest" (LeetCode #16). Implement the sort-plus-two-pointers solution and explain how you track the closest sum.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/3sum-closest/', answer: 'Sort the array; for each fixed index i, use two pointers over the remaining sorted suffix, moving the pointer on the side that reduces |sum - target|, updating a running "closest sum so far" whenever the current triplet beats it. O(n^2) time, O(1) extra space beyond sorting.', patternTags: ['two_pointers'] },
  { title: 'Sort Colors', prompt: 'Solve "Sort Colors" (LeetCode #75). Implement the one-pass Dutch national flag three-pointer partition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/sort-colors/', answer: 'Maintain low/mid/high pointers partitioning the array into [0s | 1s | unknown | 2s]; swap nums[mid] with low or high depending on its value and advance the appropriate pointers, only advancing mid when it\'s safe (a swap from high needs re-inspection of the swapped-in value). O(n) time, O(1) space, single pass.', patternTags: ['two_pointers'] },
  { title: 'Remove Duplicates from Sorted Array', prompt: 'Solve "Remove Duplicates from Sorted Array" (LeetCode #26). Implement the in-place two-pointer (read/write) solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/remove-duplicates-from-sorted-array/', answer: 'A slow "write" pointer marks the end of the deduplicated prefix; a fast "read" pointer scans forward, and whenever it finds a value different from the last written one, it\'s copied to the write pointer\'s position and the write pointer advances. O(n) time, O(1) space, exploits the array already being sorted so duplicates are always adjacent.', patternTags: ['two_pointers'] },
  { title: 'Permutation in String', prompt: 'Solve "Permutation in String" (LeetCode #567). Implement the fixed-size sliding-window + character-count comparison solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/permutation-in-string/', answer: 'Slide a window of s1\'s length across s2, maintaining a running character-frequency count for the window; the window is a permutation match whenever its frequency count exactly equals s1\'s frequency count. Update the count incrementally (add the entering character, remove the leaving one) rather than recomputing per position. O(|s2| * charset) or O(|s2|) with a match-count trick, O(charset) space.', patternTags: ['sliding_window'] },
  { title: 'Max Consecutive Ones III', prompt: 'Solve "Max Consecutive Ones III" (LeetCode #1004). Implement the sliding-window solution and explain your window-validity condition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/max-consecutive-ones-iii/', answer: 'Expand the window while tracking the count of zeros inside it; once the zero count exceeds k (allowed flips), shrink from the left until it\'s valid again (decrementing the zero count if the character leaving was a zero). Track the max window size seen. O(n) time, O(1) space.', patternTags: ['sliding_window'] },
  { title: 'Unique Paths', prompt: 'Solve "Unique Paths" (LeetCode #62). Implement the 2D (or rolling 1D) DP solution and explain your recurrence.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/unique-paths/', answer: 'dp[r][c] = dp[r-1][c] + dp[r][c-1] (paths arrive from above or from the left), with the first row and first column initialized to 1. Can be compressed to a single rolling 1D array of length = column count. O(rows*cols) time, O(cols) space with the rolling array.', patternTags: ['dynamic_programming'] },
  { title: 'Longest Common Subsequence', prompt: 'Solve "Longest Common Subsequence" (LeetCode #1143). Implement the 2D DP solution and explain your match/no-match transition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/longest-common-subsequence/', answer: 'dp[i][j] = dp[i-1][j-1] + 1 when the characters match, otherwise max(dp[i-1][j], dp[i][j-1]) — either skip a character from the first string or the second. O(m*n) time, O(m*n) space (reducible to O(min(m,n)) with a rolling row).', patternTags: ['dynamic_programming'] },
  { title: 'Partition Equal Subset Sum', prompt: 'Solve "Partition Equal Subset Sum" (LeetCode #416). Implement the 0/1-knapsack-style DP solution and explain how you reduce it to a subset-sum problem.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/partition-equal-subset-sum/', answer: 'If the total sum is odd, no equal partition exists. Otherwise, this is exactly "does a subset sum to total/2?" — a 0/1 knapsack reachability DP over a boolean array of size total/2+1, updated in reverse order per item to enforce each item is used at most once. O(n * total/2) time, O(total/2) space.', patternTags: ['dynamic_programming'] },
  { title: 'Decode Ways', prompt: 'Solve "Decode Ways" (LeetCode #91). Implement the O(1)-space DP solution and explain your one-digit/two-digit transition, including the \'0\' edge case.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/decode-ways/', answer: 'ways(i) = ways(i-1) if s[i] is a valid single digit (1-9), plus ways(i-2) if s[i-1..i] forms a valid two-digit code (10-26). A lone \'0\' contributes nothing to the one-digit case, which is the trickiest edge case to get right. Track only the last two running values instead of a full array. O(n) time, O(1) space.', patternTags: ['dynamic_programming'] },
  { title: 'Maximum Product Subarray', prompt: 'Solve "Maximum Product Subarray" (LeetCode #152). Implement the running max/min DP solution and explain why you must track both.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/maximum-product-subarray/', answer: 'Track both a running max and running min product ending at the current index, since multiplying by a negative number can flip the most negative running product into the new maximum. At each step, the new max/min are computed from candidates (current value alone, current * old max, current * old min). O(n) time, O(1) space.', patternTags: ['dynamic_programming'] },
  { title: 'K Closest Points to Origin', prompt: 'Solve "K Closest Points to Origin" (LeetCode #973). Implement the max-heap-of-size-k solution and explain why a max-heap (not a min-heap) is used here.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/k-closest-points-to-origin/', answer: 'Maintain a max-heap of size k keyed by squared distance (avoids a sqrt); when the heap exceeds k, pop the farthest point. A max-heap is used (not min) because you always want to evict the *worst* of the current top-k candidates as better ones arrive. O(n log k) time, O(k) space.', patternTags: ['heap_priority_queue'] },
  { title: 'Find Median from Data Stream', prompt: 'Solve "Find Median from Data Stream" (LeetCode #295). Implement the two-heap (max-heap for the lower half, min-heap for the upper half) solution.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-median-from-data-stream/', answer: 'Keep a max-heap holding the smaller half of numbers and a min-heap holding the larger half, rebalancing after each insert so their sizes differ by at most one. The median is either the max-heap\'s top (odd total) or the average of both heaps\' tops (even total). O(log n) insert, O(1) median query.', patternTags: ['heap_priority_queue'] },
  { title: 'Pacific Atlantic Water Flow', prompt: 'Solve "Pacific Atlantic Water Flow" (LeetCode #417). Implement the reverse-multi-source-BFS/DFS solution and explain why you flow "uphill" from the oceans instead of downhill from every cell.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/pacific-atlantic-water-flow/', answer: 'Instead of checking every cell\'s path to both oceans (expensive), run two multi-source BFS/DFS flood fills starting from all Pacific-adjacent and all Atlantic-adjacent cells respectively, flowing "uphill" (to equal-or-higher neighbors, since real water flows downhill, so reachability from the ocean is the reverse relation). The answer is the intersection of both reachable sets. O(rows*cols) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Rotting Oranges', prompt: 'Solve "Rotting Oranges" (LeetCode #994). Implement the multi-source BFS solution and explain how you track elapsed time.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/rotting-oranges/', answer: 'Seed a BFS queue with all initially-rotten oranges at once (multi-source), then process level by level, incrementing a minute counter per level and rotting fresh neighbors. If any fresh orange remains unreachable after BFS completes, return -1; otherwise the minute counter is the answer. O(rows*cols) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Word Ladder', prompt: 'Solve "Word Ladder" (LeetCode #127). Implement the BFS shortest-path solution over one-letter-different word transformations.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/word-ladder/', answer: 'Model each word as a graph node with edges to every word one letter apart; BFS from the start word gives shortest transformation length by level, stopping the moment the end word is dequeued. Speed up neighbor generation by trying all 26 substitutions per character position instead of comparing against every dictionary word. O(words * wordLength * 26) time.', patternTags: ['graph_traversal'] },
  { title: 'Letter Combinations of a Phone Number', prompt: 'Solve "Letter Combinations of a Phone Number" (LeetCode #17). Implement the backtracking solution over the digit-to-letters mapping.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/letter-combinations-of-a-phone-number/', answer: 'DFS one digit at a time, branching into each letter that digit maps to, appending to a shared path string and popping (backtracking) after each branch returns. Base case: path length equals the input length, so record it. O(4^n) worst case (digits mapping to 4 letters), O(n) recursion depth.', patternTags: ['backtracking'] },
  { title: 'Palindrome Partitioning', prompt: 'Solve "Palindrome Partitioning" (LeetCode #131). Implement the backtracking solution and explain your palindrome-prefix check.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/palindrome-partitioning/', answer: 'At each starting index, try every possible palindromic prefix ending at each later index, recursing on the remainder if the prefix is a palindrome, and backtracking (popping the choice) afterward. Precomputing an is-palindrome table for all substrings avoids redundant checks across branches. O(n * 2^n) worst case.', patternTags: ['backtracking'] },
  { title: 'Best Time to Buy and Sell Stock II', prompt: 'Solve "Best Time to Buy and Sell Stock II" (LeetCode #122). Implement the greedy "capture every uphill move" solution and explain why it\'s optimal.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/best-time-to-buy-and-sell-stock-ii/', answer: 'Sum every positive day-to-day price difference (price[i] - price[i-1] whenever positive); this is equivalent to buying at the start of every uphill run and selling at its peak, and it provably matches the optimal multi-transaction profit since any profitable multi-day hold can be decomposed into consecutive single-day gains. O(n) time, O(1) space.', patternTags: ['greedy'] },
  { title: 'Partition Labels', prompt: 'Solve "Partition Labels" (LeetCode #763). Implement the greedy last-occurrence-index solution and explain how you decide where each partition ends.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/partition-labels/', answer: 'Precompute each character\'s last occurrence index in one pass. Scan again tracking the current partition\'s farthest-required end (max of last-occurrence for every character seen so far in this partition); when the current index reaches that farthest end, close the partition. O(n) time, O(charset) space.', patternTags: ['greedy'] },
  { title: 'Sum of Two Integers', prompt: 'Solve "Sum of Two Integers" (LeetCode #371). Implement addition using only bitwise operators and explain your carry-propagation loop.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/sum-of-two-integers/', answer: 'XOR gives the sum-without-carry at each bit position; AND-then-left-shift gives the carry that needs to be added in. Repeat "sum = a^b, carry = (a&b)<<1, a=sum, b=carry" until there is no carry left. Requires care with language-specific fixed-width integer overflow/sign handling. O(1) time (bounded by integer width).', patternTags: ['bit_manipulation'] },
  { title: 'Reverse Bits', prompt: 'Solve "Reverse Bits" (LeetCode #190). Implement the bit-by-bit reversal solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/reverse-bits/', answer: 'Iterate all 32 bit positions; at each step, shift the result left by one, OR in the current lowest bit of the input, then shift the input right by one. After 32 iterations the result holds the bit-reversed value. O(1) time (fixed 32 iterations).', patternTags: ['bit_manipulation'] },
  { title: 'Invert Binary Tree', prompt: 'Solve "Invert Binary Tree" (LeetCode #226). Implement the recursive solution and explain the base case.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/invert-binary-tree/', answer: 'Recursively swap each node\'s left and right children, then recurse into both (now-swapped) subtrees; the base case is a null node, which returns immediately. Order doesn\'t matter (swap-then-recurse or recurse-then-swap both work since it\'s a pure structural mutation). O(n) time, O(h) space.', patternTags: ['tree_dfs'] },
  { title: 'Lowest Common Ancestor of a Binary Search Tree', prompt: 'Solve "Lowest Common Ancestor of a Binary Search Tree" (LeetCode #235). Implement the solution that exploits BST ordering instead of a generic tree LCA algorithm.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/lowest-common-ancestor-of-a-binary-search-tree/', answer: 'Starting at the root, if both target values are less than the current node, go left; if both are greater, go right; the first node where the targets diverge (one <=, one >=) is the LCA — no need to search both subtrees like the generic binary-tree LCA algorithm, since BST ordering tells you which side each target is on. O(h) time, O(1) space iteratively.', patternTags: ['tree_dfs'] },

  // MOM-048: DSA ladder batch 4 (final batch toward the 150-item Gate-3 target).
  // Rounds out remaining gaps and adds a genuine hard tier (13 of 50 items here are
  // hard) so the ladder isn't just easy/medium depth. Same D-008 rule throughout.
  { title: '4Sum', prompt: 'Solve "4Sum" (LeetCode #18). Implement the sort-plus-nested-two-pointers generalization of 3Sum.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/4sum/', answer: 'Sort the array; fix the first two indices with nested loops (skipping duplicates), then two-pointer the remaining sorted suffix for the last two values, same as 3Sum but one level deeper. Prune early when the smallest possible sum already exceeds target or the largest possible sum is still below it. O(n^3) time, O(1) extra space beyond sorting.', patternTags: ['two_pointers'] },
  { title: 'Two Sum II - Input Array Is Sorted', prompt: 'Solve "Two Sum II - Input Array Is Sorted" (LeetCode #167). Implement the two-pointer solution and explain why it beats the hash-map approach here.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/two-sum-ii-input-array-is-sorted/', answer: 'Since the array is already sorted, two pointers from both ends can move toward the target sum in O(1) space: move left forward if the sum is too small, right backward if too large. A hash map (as in the unsorted Two Sum) would also work but needs O(n) extra space, which sorted input lets you avoid.', patternTags: ['two_pointers'] },
  { title: 'Boats to Save People', prompt: 'Solve "Boats to Save People" (LeetCode #881). Implement the sort-plus-two-pointers greedy pairing solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/boats-to-save-people/', answer: 'Sort by weight; try to pair the lightest and heaviest remaining people in one boat. If they fit together, advance both pointers; otherwise the heaviest goes alone and only that pointer advances. Greedy is optimal because the heaviest person always needs a boat, and pairing them with the lightest available person never wastes capacity. O(n log n) time.', patternTags: ['two_pointers'] },
  { title: 'Sliding Window Maximum', prompt: 'Solve "Sliding Window Maximum" (LeetCode #239). Implement the monotonic-deque solution and explain what invariant the deque maintains.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/sliding-window-maximum/', answer: 'Maintain a deque of indices with strictly decreasing values; before adding the current index, pop smaller values from the back (they can never be the max again while the current, larger value is in the window). Pop the front if it has fallen outside the window. The front of the deque is always the current window\'s max. O(n) time (each index pushed/popped once), O(k) space.', patternTags: ['sliding_window', 'monotonic_stack'] },
  { title: 'Fruit Into Baskets', prompt: 'Solve "Fruit Into Baskets" (LeetCode #904). Implement the sliding-window solution and explain how it reduces to "longest subarray with at most 2 distinct values".', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/fruit-into-baskets/', answer: 'The two-basket constraint is exactly "longest contiguous subarray with at most 2 distinct fruit types": expand the window, track counts per type in a map, and shrink from the left whenever a third distinct type appears until only 2 remain. O(n) time, O(1) space (at most 3 map entries at any time).', patternTags: ['sliding_window'] },
  { title: 'Minimum Size Subarray Sum', prompt: 'Solve "Minimum Size Subarray Sum" (LeetCode #209). Implement the sliding-window solution and explain your shrink condition.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/minimum-size-subarray-sum/', answer: 'Expand the window accumulating a running sum; whenever the sum meets or exceeds the target, shrink from the left as far as possible while still valid, recording the smallest window length seen along the way. Works because all values are positive, so shrinking only ever decreases the sum monotonically. O(n) time, O(1) space.', patternTags: ['sliding_window'] },
  { title: 'Palindrome Linked List', prompt: 'Solve "Palindrome Linked List" (LeetCode #234). Implement the O(1)-space solution using fast/slow pointers plus in-place reversal of the second half.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/palindrome-linked-list/', answer: 'Find the middle with fast/slow pointers, reverse the second half in place, then compare it against the first half node by node. Optionally re-reverse the second half afterward to restore the list. O(n) time, O(1) space — avoids the simpler O(n)-space array-copy approach.', patternTags: ['fast_slow_pointers'] },
  { title: 'Find the Duplicate Number', prompt: 'Solve "Find the Duplicate Number" (LeetCode #287). Implement Floyd\'s cycle detection treating the array as a linked list via value-as-next-index.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-the-duplicate-number/', answer: 'Treat nums[i] as a pointer to index nums[i] — a duplicate value creates a cycle in this implicit linked list. Run standard fast/slow cycle detection to find the meeting point, then reset one pointer to the start and advance both one step at a time; they meet exactly at the cycle\'s entrance, which is the duplicate value. O(n) time, O(1) space, no array mutation.', patternTags: ['fast_slow_pointers', 'cyclic_sort'] },
  { title: 'Meeting Rooms II', prompt: 'Solve "Meeting Rooms II" (LeetCode #253). Implement the min-heap-of-end-times solution and explain what the heap size represents.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/meeting-rooms-ii/', answer: 'Sort meetings by start time; maintain a min-heap of currently-occupied rooms\' end times. For each meeting, if the earliest-ending room (heap top) ends at or before this meeting\'s start, reuse that room (pop and push the new end time); otherwise allocate a new room (push without popping). The heap\'s size at any point is the rooms in use; its max size across the scan is the answer. O(n log n) time, O(n) space.', patternTags: ['merge_intervals', 'heap_priority_queue'] },
  { title: 'Interval List Intersections', prompt: 'Solve "Interval List Intersections" (LeetCode #986). Implement the two-pointer merge-style solution over both sorted interval lists.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/interval-list-intersections/', answer: 'Walk both lists with a pointer each; the overlap of the current pair (if any) is [max(starts), min(ends)] — record it if start<=end. Advance whichever interval ends first, since it can no longer overlap anything later in the other list. O(m+n) time, O(1) extra space beyond output.', patternTags: ['merge_intervals', 'two_pointers'] },
  { title: 'Kth Missing Positive Number', prompt: 'Solve "Kth Missing Positive Number" (LeetCode #1539). Implement the binary-search-on-missing-count solution and explain the "missing so far" formula.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/kth-missing-positive-number/', answer: 'At sorted index i (0-based), the count of positives missing before arr[i] is arr[i] - (i+1) (how far ahead of its "expected" value it is). Binary search for the first index where this missing-count is >= k; the answer is derivable from the previous index\'s missing-count plus the remaining gap. O(log n) time, O(1) space (an O(n) linear scan also works and is a fine first pass).', patternTags: ['cyclic_sort', 'binary_search'] },
  { title: 'Capacity To Ship Packages Within D Days', prompt: 'Solve "Capacity To Ship Packages Within D Days" (LeetCode #1011). Implement binary search on the answer (ship capacity) and explain your feasibility check.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/capacity-to-ship-packages-within-d-days/', answer: 'Binary search over possible capacities (from max single weight to total weight); for a candidate capacity, greedily count days needed by packing packages until adding one more would exceed capacity. Feasibility (days needed <= D) is monotonic in capacity, so binary search on the answer applies. O(n log(sum of weights)) time.', patternTags: ['binary_search', 'greedy'] },
  { title: 'Split Array Largest Sum', prompt: 'Solve "Split Array Largest Sum" (LeetCode #410). Implement binary search on the answer and explain how it\'s the same shape as Capacity To Ship Packages.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/split-array-largest-sum/', answer: 'Identical structure to "Capacity To Ship Packages Within D Days": binary search over the candidate "largest subarray sum", with a greedy feasibility check counting how many subarrays are needed to keep every subarray sum <= the candidate. Recognizing this pattern-matches a problem you\'ve already solved is the key interview skill here. O(n log(sum)) time.', patternTags: ['binary_search', 'greedy'] },
  { title: 'Find Peak Element', prompt: 'Solve "Find Peak Element" (LeetCode #162). Implement the binary search solution and explain why it works even though the array isn\'t sorted.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-peak-element/', answer: 'At mid, if nums[mid] < nums[mid+1], a peak must exist to the right (values are trending up, and the array\'s edges count as -infinity); otherwise a peak exists at mid or to its left. This works without full sortedness because the "trending toward a peak" comparison is a local, not global, property. O(log n) time, O(1) space.', patternTags: ['binary_search'] },
  { title: 'Populating Next Right Pointers in Each Node', prompt: 'Solve "Populating Next Right Pointers in Each Node" (LeetCode #116). Implement the O(1)-extra-space level-linking solution using the already-connected previous level.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/populating-next-right-pointers-in-each-node/', answer: 'For a perfect binary tree, once level i\'s `next` pointers are set, you can traverse level i using those pointers alone (no queue needed) to link level i+1\'s children as you go: node.left.next = node.right, and node.right.next = node.next.left (if node.next exists). O(n) time, O(1) extra space — beats a standard BFS queue\'s O(w) space.', patternTags: ['tree_bfs'] },
  { title: 'Binary Tree Maximum Path Sum', prompt: 'Solve "Binary Tree Maximum Path Sum" (LeetCode #124). Implement the post-order DFS solution and explain the difference between "path through this node" and "the value this call returns".', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/binary-tree-maximum-path-sum/', answer: 'At each node, compute the best single-branch contribution downward (max(0, left), max(0, right)) — this is what the recursive call *returns* to its parent, since a path continuing upward can only take one branch. Separately, update a global max using left+right+node.value, representing the best path that turns at this node (which can never be returned upward). O(n) time, O(h) space.', patternTags: ['tree_dfs'] },
  { title: 'Construct Binary Tree from Preorder and Inorder Traversal', prompt: 'Solve "Construct Binary Tree from Preorder and Inorder Traversal" (LeetCode #105). Implement the recursive solution and explain how preorder\'s first element and inorder\'s split point work together.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/construct-binary-tree-from-preorder-and-inorder-traversal/', answer: 'Preorder\'s first remaining element is always the current subtree\'s root; find that value\'s index in inorder — everything left of it is the left subtree\'s inorder sequence, everything right is the right subtree\'s. Recurse on the corresponding preorder slices. A hash map from value to inorder index makes each split O(1) instead of O(n). O(n) time with the map, O(n) space.', patternTags: ['tree_dfs'] },
  { title: 'Serialize and Deserialize Binary Tree', prompt: 'Solve "Serialize and Deserialize Binary Tree" (LeetCode #297). Implement preorder serialization with null markers and the matching recursive deserializer.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/serialize-and-deserialize-binary-tree/', answer: 'Serialize via preorder DFS, writing an explicit sentinel (e.g. "#") for null children so the traversal is unambiguous to reverse. Deserialize by consuming tokens in the same preorder order: read a token, if it\'s the sentinel return null, otherwise create a node and recursively fill its left then right children from the remaining token stream. O(n) time and space both ways.', patternTags: ['tree_dfs'] },
  { title: 'Surrounded Regions', prompt: 'Solve "Surrounded Regions" (LeetCode #130). Implement the border-first DFS/BFS solution and explain why you start from the border instead of scanning every cell.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/surrounded-regions/', answer: 'Any \'O\' connected to the border can never be fully surrounded, so flood-fill from every border \'O\' first, marking them safe. Afterward, flip every remaining unmarked \'O\' to \'X\' (truly surrounded) and restore the marked ones back to \'O\'. Starting from the border avoids the harder problem of checking reachability-to-border from arbitrary interior cells. O(rows*cols) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Is Graph Bipartite?', prompt: 'Solve "Is Graph Bipartite?" (LeetCode #785). Implement the two-coloring BFS/DFS solution and explain your conflict check.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/is-graph-bipartite/', answer: 'BFS/DFS from each uncolored node, alternating colors between a node and its neighbors; if a neighbor is already colored the same as the current node, the graph is not bipartite. Must restart from a new uncolored node for each disconnected component. O(V+E) time and space.', patternTags: ['graph_traversal'] },
  { title: 'Network Delay Time', prompt: 'Solve "Network Delay Time" (LeetCode #743). Implement Dijkstra\'s algorithm with a min-heap and explain why it fits this weighted-graph shortest-path problem.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/network-delay-time/', answer: 'Classic single-source shortest path with non-negative weights: a min-heap keyed by current known distance, popping the closest unvisited node each time and relaxing its outgoing edges. The answer is the max distance across all nodes once done (or -1 if any node is unreachable). O(E log V) time, O(V+E) space.', patternTags: ['graph_traversal', 'heap_priority_queue'] },
  { title: 'Find Eventual Safe States', prompt: 'Solve "Find Eventual Safe States" (LeetCode #802). Implement the reverse-graph topological (Kahn\'s-style) solution and explain what "safe" means in terms of terminal nodes.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-eventual-safe-states/', answer: 'A node is "safe" if every path from it eventually reaches a terminal node (no outgoing edges) without looping forever. Reverse all edges, then run Kahn\'s algorithm treating out-degree-zero nodes (in the *original* graph) as the starting frontier, peeling nodes whose remaining out-edges (tracked via the reversed in-edges) all resolve to safe nodes. O(V+E) time and space.', patternTags: ['topological_sort', 'graph_traversal'] },
  { title: 'Most Stones Removed with Same Row or Column', prompt: 'Solve "Most Stones Removed with Same Row or Column" (LeetCode #947). Implement the union-find-over-rows-and-columns solution and explain the final formula.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/most-stones-removed-with-same-row-or-column/', answer: 'Union each stone\'s row-id and column-id (using offset row/col namespaces to share one union-find structure); stones in the same connected component can all be reduced to one survivor. The answer is (total stones - number of distinct components), since exactly one stone per component must remain. O(n * alpha(n)) time, O(n) space.', patternTags: ['union_find'] },
  { title: 'Smallest String With Swaps', prompt: 'Solve "Smallest String With Swaps" (LeetCode #1202). Implement union-find to group swappable indices, then explain how you reorder each group.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/smallest-string-with-swaps/', answer: 'Union every pair of indices connected by a swap; indices in the same component can be freely rearranged among themselves (since swaps within a connected set can realize any permutation of it). For each component, collect its characters, sort them, and place them back into the component\'s indices in sorted order (smallest index gets smallest character). O(n log n) time, O(n) space.', patternTags: ['union_find'] },
  { title: 'Word Search', prompt: 'Solve "Word Search" (LeetCode #79). Implement the backtracking DFS over the grid and explain how you mark/unmark visited cells.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/word-search/', answer: 'DFS from each starting cell matching the word character by character, temporarily marking the current cell as visited (e.g. overwrite with a sentinel) before recursing into its 4 neighbors, then restoring it (unmark/backtrack) once that branch is exhausted so other paths can reuse the cell. O(rows*cols*4^L) worst case (L = word length).', patternTags: ['backtracking'] },
  { title: 'Combination Sum II', prompt: 'Solve "Combination Sum II" (LeetCode #40). Implement the backtracking solution and explain how it differs from Combination Sum in handling duplicate candidates.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/combination-sum-ii/', answer: 'Unlike Combination Sum, each candidate can be used at most once, so recursion advances to the next index (not the same one) after including a value. Sort first, and at each recursion level skip over duplicate candidate values (except the first occurrence) to avoid generating the same combination twice. O(2^n) worst case, pruned heavily by sorting + early termination.', patternTags: ['backtracking'] },
  { title: 'Sudoku Solver', prompt: 'Solve "Sudoku Solver" (LeetCode #37). Implement the backtracking solution with row/column/box constraint tracking.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/sudoku-solver/', answer: 'Maintain boolean "used" sets per row, column, and 3x3 box for O(1) constraint checks. DFS to the next empty cell, try each digit 1-9 that\'s currently valid for that cell\'s row/column/box, place it and recurse; if no digit leads to a full solution, backtrack (unmark and try the next digit). Precomputing the constraint sets up front avoids rescanning the board on every check.', patternTags: ['backtracking'] },
  { title: 'Candy', prompt: 'Solve "Candy" (LeetCode #135). Implement the two-pass greedy solution and explain why one pass alone isn\'t enough.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/candy/', answer: 'Left-to-right pass: give a child one more candy than their left neighbor if their rating is higher. Right-to-left pass: take the max of the current value and (right neighbor\'s candies + 1) if this child\'s rating is higher than the right neighbor\'s. A single directional pass can\'t satisfy both left and right neighbor constraints simultaneously, which is why two passes are needed. O(n) time, O(n) space.', patternTags: ['greedy'] },
  { title: 'Queue Reconstruction by Height', prompt: 'Solve "Queue Reconstruction by Height" (LeetCode #406). Implement the sort-then-insert greedy solution and explain your insertion rule.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/queue-reconstruction-by-height/', answer: 'Sort people by height descending, and by k (number of taller-or-equal people in front) ascending as a tiebreak. Insert each person into the result at index k: since every person inserted so far is at least as tall, inserting at position k automatically satisfies their "k taller people in front" constraint, and later (shorter) insertions never affect already-placed taller people\'s counts. O(n^2) time from list insertion, O(n) space.', patternTags: ['greedy'] },
  { title: 'Find Pivot Index', prompt: 'Solve "Find Pivot Index" (LeetCode #724). Implement the prefix-sum solution and explain your left-sum/right-sum comparison.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/find-pivot-index/', answer: 'Compute the total sum once; scan left to right tracking a running left-sum, and at each index derive right-sum = total - leftSum - nums[i]. The first index where leftSum equals rightSum is the pivot. O(n) time, O(1) space — avoids recomputing sums from scratch per candidate index.', patternTags: ['prefix_sum'] },
  { title: 'Minimum Value to Get Positive Step by Step Sum', prompt: 'Solve "Minimum Value to Get Positive Step by Step Sum" (LeetCode #1413). Implement the running-minimum-prefix-sum solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/minimum-value-to-get-positive-step-by-step-sum/', answer: 'Track the running prefix sum and its minimum value across the whole scan; the answer is 1 - minPrefixSum (or 1 if the minimum is already >= 0), since startValue + minPrefixSum must be at least 1 at the worst point in the sequence. O(n) time, O(1) space.', patternTags: ['prefix_sum'] },
  { title: 'Single Number II', prompt: 'Solve "Single Number II" (LeetCode #137). Implement the bit-counting-mod-3 solution and explain why plain XOR (as in Single Number) doesn\'t work here.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/single-number-ii/', answer: 'Every other number appears exactly 3 times, so plain XOR (which relies on pairs canceling) doesn\'t apply. Instead, for each bit position, sum how many numbers have that bit set; if the count isn\'t a multiple of 3, the single number has that bit set. O(32n) = O(n) time, O(1) space.', patternTags: ['bit_manipulation'] },
  { title: 'Bitwise AND of Numbers Range', prompt: 'Solve "Bitwise AND of Numbers Range" (LeetCode #201). Implement the common-prefix-shift solution and explain what it computes.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/bitwise-and-of-numbers-range/', answer: 'Any bit that differs somewhere between m and n will be zero in the final AND (since the range includes both a 0 and a 1 at that position across the full range of numbers). Right-shift both m and n together, counting shifts, until they\'re equal — that\'s their common binary prefix — then left-shift the result back by the same count. O(bit width) time, O(1) space.', patternTags: ['bit_manipulation'] },
  { title: 'Word Search II', prompt: 'Solve "Word Search II" (LeetCode #212). Implement the trie + backtracking DFS solution and explain why a trie beats running Word Search once per target word.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/word-search-ii/', answer: 'Insert all target words into a trie, then DFS from every grid cell simultaneously walking the trie (not a single word) — the moment a trie node marked end-of-word is reached, record that word. This shares work across words with common prefixes instead of re-running a full grid DFS per word, and pruning dead trie branches (removing found words / childless nodes) keeps later searches cheap. O(rows*cols*4^L) worst case, much better in practice.', patternTags: ['trie', 'backtracking'] },
  { title: 'Largest Rectangle in Histogram', prompt: 'Solve "Largest Rectangle in Histogram" (LeetCode #84). Implement the monotonic-stack solution and explain what each popped bar\'s rectangle represents.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/largest-rectangle-in-histogram/', answer: 'Maintain a stack of increasing bar heights (by index); when a shorter bar appears, pop taller bars and compute the rectangle each one could form using its height and a width spanning back to the new stack top (or the start) — that popped bar\'s tallest possible rectangle is now fully determined since it can\'t extend further right. Append a sentinel zero-height bar at the end to flush the stack. O(n) time (each bar pushed/popped once), O(n) space.', patternTags: ['monotonic_stack'] },
  { title: 'Remove K Digits', prompt: 'Solve "Remove K Digits" (LeetCode #402). Implement the monotonic-increasing-stack (greedy digit removal) solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/remove-k-digits/', answer: 'Build the result digit by digit with a stack: before pushing the current digit, pop any larger digit from the stack top while removals remain (a smaller digit earlier always beats a larger one, for the same digit count remaining). After the scan, remove any leftover count from the end, then strip leading zeros. O(n) time, O(n) space.', patternTags: ['monotonic_stack', 'greedy'] },
  { title: 'Edit Distance', prompt: 'Solve "Edit Distance" (LeetCode #72). Implement the 2D DP solution and explain your insert/delete/replace transition.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/edit-distance/', answer: 'dp[i][j] = dp[i-1][j-1] if the characters match; otherwise 1 + min(dp[i-1][j] (delete), dp[i][j-1] (insert), dp[i-1][j-1] (replace)). Base rows/columns are the cost of turning an empty string into a prefix (pure inserts/deletes). O(m*n) time and space, reducible to O(min(m,n)) space with a rolling row.', patternTags: ['dynamic_programming'] },
  { title: 'Regular Expression Matching', prompt: 'Solve "Regular Expression Matching" (LeetCode #10). Implement the 2D DP solution supporting \'.\' and \'*\' and explain your \'*\' transition.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/regular-expression-matching/', answer: 'dp[i][j] tracks whether s[0:i] matches p[0:j]. A \'*\' at p[j-1] means: either treat "x*" as matching zero occurrences (dp[i][j-2]), or — if the preceding character matches s[i-1] — as matching one more occurrence (dp[i-1][j]). Without \'*\', it\'s a straightforward character-or-\'.\' match carried from dp[i-1][j-1]. O(m*n) time and space.', patternTags: ['dynamic_programming'] },
  { title: 'Burst Balloons', prompt: 'Solve "Burst Balloons" (LeetCode #312). Implement the interval DP solution and explain why you think about the *last* balloon burst in a range, not the first.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/burst-balloons/', answer: 'Pad the array with 1s at both ends. dp[l][r] = max coins from bursting every balloon strictly between l and r, choosing which balloon k is burst *last* in that range: dp[l][r] = max over k of dp[l][k] + dp[k][r] + nums[l]*nums[k]*nums[r]. Thinking "last burst" (not first) makes the two sub-ranges independent, since nums[l] and nums[r] are guaranteed still present as k\'s neighbors at that point. O(n^3) time, O(n^2) space.', patternTags: ['dynamic_programming'] },
  { title: 'Minimum Path Sum', prompt: 'Solve "Minimum Path Sum" (LeetCode #64). Implement the 2D (or rolling 1D) DP solution.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/minimum-path-sum/', answer: 'dp[r][c] = grid[r][c] + min(dp[r-1][c], dp[r][c-1]), with the first row/column initialized by accumulating along the single available direction. Same recurrence family as Unique Paths, but tracking a minimum sum instead of a path count. O(rows*cols) time, O(cols) space with a rolling row.', patternTags: ['dynamic_programming'] },
  { title: 'Coin Change II', prompt: 'Solve "Coin Change II" (LeetCode #518). Implement the DP-counting-combinations solution and explain why the coin loop must be on the outside.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/coin-change-ii/', answer: 'dp[amount] = number of ways to make that amount. Loop over coins in the outer loop and amounts in the inner loop (ascending), adding dp[amount-coin] to dp[amount] — this ordering counts each *combination* once (order doesn\'t matter), whereas looping amounts on the outside would count *permutations* (order matters) instead, over-counting. O(coins * amount) time, O(amount) space.', patternTags: ['dynamic_programming'] },
  { title: 'Reorganize String', prompt: 'Solve "Reorganize String" (LeetCode #767). Implement the max-heap-by-frequency greedy solution and explain your feasibility precheck.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/reorganize-string/', answer: 'If the most frequent character\'s count exceeds ceil(length/2), no valid arrangement exists — return empty. Otherwise, repeatedly pop the two most frequent remaining characters from a max-heap, append one, hold the other back one round (so the same character is never placed adjacent to itself), and push counts back in. O(n log k) time (k = alphabet size), O(k) space.', patternTags: ['heap_priority_queue', 'greedy'] },
  { title: 'Ugly Number II', prompt: 'Solve "Ugly Number II" (LeetCode #264). Implement the three-pointer DP solution and explain why a naive heap-based approach is less elegant here.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/ugly-number-ii/', answer: 'Build ugly numbers in increasing order with dp[1]=1 and three pointers (for factors 2, 3, 5) each tracking which prior ugly number to multiply next; at each step take the min of the three candidates and advance whichever pointer(s) produced that min (advancing all matching pointers avoids duplicates). O(n) time, O(n) space — a min-heap works too but needs explicit duplicate-skipping and more memory churn.', patternTags: ['dynamic_programming', 'heap_priority_queue'] },
  { title: 'Rotate List', prompt: 'Solve "Rotate List" (LeetCode #61). Implement the solution that closes the list into a cycle and reopens it at the right point.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/rotate-list/', answer: 'Find the length and connect the tail to the head, forming a cycle. Compute the effective rotation as k mod length (handles k larger than the list), then walk (length - k mod length) steps from the head to find the new tail, and break the cycle there — the node after it becomes the new head. O(n) time, O(1) space.', patternTags: ['linked_list_reversal'] },
  { title: 'Word Break II', prompt: 'Solve "Word Break II" (LeetCode #140). Implement the backtracking-with-memoization solution and explain why memoization is essential here (unlike plain Word Break).', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/word-break-ii/', answer: 'Unlike Word Break (which only needs a yes/no DP), this needs every valid segmentation, so it\'s naturally backtracking: try each dictionary-word prefix, recurse on the remainder, and combine results. Without memoizing "all segmentations of this suffix" by starting index, overlapping subproblems get recomputed exponentially — memoization turns it back into roughly one computation per distinct suffix. Exponential worst case in output size, but the underlying subproblem count is polynomial.', patternTags: ['dynamic_programming', 'backtracking'] },
  { title: 'Flood Fill', prompt: 'Solve "Flood Fill" (LeetCode #733). Implement the DFS/BFS solution and explain the edge case where the new color equals the old color.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/flood-fill/', answer: 'DFS/BFS from the starting cell, recoloring matching-color neighbors and recursing. If the new color equals the starting cell\'s original color, do nothing (or you\'ll infinite-loop revisiting already-"recolored" cells that never actually changed). O(rows*cols) time and space worst case.', patternTags: ['graph_traversal'] },
  { title: 'Restore IP Addresses', prompt: 'Solve "Restore IP Addresses" (LeetCode #93). Implement the backtracking solution and explain your per-segment validity checks.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/restore-ip-addresses/', answer: 'Backtrack choosing 1-3 characters at a time for each of the 4 segments; a segment is valid only if it has no leading zero (unless it\'s exactly "0") and its numeric value is 0-255. Prune branches immediately when a segment is invalid or when remaining characters can\'t possibly fill the remaining segments (too many or too few). O(1) effectively (bounded by 4 segments x 3 choices each), since IP addresses have fixed structure.', patternTags: ['backtracking'] },
  { title: 'Partition List', prompt: 'Solve "Partition List" (LeetCode #86). Implement the two-dummy-list solution and explain how you preserve relative order.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/partition-list/', answer: 'Build two separate chains (via dummy heads) while scanning once: nodes less than x go to one chain, the rest to another, each appended in the order encountered (preserving relative order within each chain, as required). Finally splice the second chain onto the end of the first. O(n) time, O(1) extra space (reuses existing nodes).', patternTags: ['linked_list_reversal'] },
  { title: 'Sliding Window Median', prompt: 'Solve "Sliding Window Median" (LeetCode #480). Implement the two-heap (or balanced multiset) solution and explain the extra bookkeeping this problem needs versus Find Median from Data Stream.', type: 'dsa', difficulty: 'hard', topic: 8, sourceUrl: 'https://leetcode.com/problems/sliding-window-median/', answer: 'Same two-heap idea as Find Median from Data Stream, but now elements must also be *removed* as the window slides — since heaps don\'t support efficient arbitrary removal, track "lazily deleted" counts per value and clean up heap tops when they match a pending deletion, rebalancing heap sizes accounting for pending deletions too. O(n log k) time, O(k) space.', patternTags: ['heap_priority_queue', 'sliding_window'] },
  { title: 'Hamming Distance', prompt: 'Solve "Hamming Distance" (LeetCode #461). Implement the XOR-then-popcount solution.', type: 'dsa', difficulty: 'easy', topic: 8, sourceUrl: 'https://leetcode.com/problems/hamming-distance/', answer: 'XOR the two numbers — every differing bit position becomes a 1 in the result. Count the set bits in that XOR result (e.g. via Brian Kernighan\'s n & (n-1) trick) to get the Hamming distance directly. O(bit width) time, O(1) space.', patternTags: ['bit_manipulation'] },
  { title: 'Course Schedule IV', prompt: 'Solve "Course Schedule IV" (LeetCode #1462). Implement a prerequisite reachability solution and explain when you would choose Floyd-Warshall versus DFS memoization.', type: 'dsa', difficulty: 'medium', topic: 8, sourceUrl: 'https://leetcode.com/problems/course-schedule-iv/', answer: 'Model courses as a directed graph from prerequisite to dependent course. For many reachability queries, either precompute transitive closure with Floyd-Warshall/bitsets, or run DFS with memoization from each queried prerequisite to cache what it can reach. Floyd-Warshall is simple when n is small and query volume is high; DFS memoization is often leaner on sparse graphs. After precomputation, each query is an O(1) lookup.', patternTags: ['graph_traversal', 'topological_sort'] },
  // MOM-052/053/054: final CS Fundamentals seed item, bringing the total from 149 to
  // the plan §8.2 target of 150.
  { title: 'Backpressure in a Node.js readable stream pipeline', prompt: 'A Node.js service pipes a fast-producing readable stream into a slower writable destination and memory usage climbs unbounded under load. Explain what backpressure means here, why `.pipe()` alone might not be enough if you fan out to multiple writables, and how you would fix it.', type: 'nodejs', difficulty: 'medium', topic: 0, answer: 'Backpressure is the signal a writable stream gives (via `write()` returning false, or the drain event) that its internal buffer is full and the producer should pause. `.pipe()` already respects backpressure for a single writable — it pauses the readable until drain fires. The bug case is usually manual writes (calling `.write()` in a data handler without checking the return value) or fanning out to N writables where one is slow: you must pause the readable (or use `pipeline()`/manual write()-return-value checks) and resume only once *all* destinations have drained, not just the fastest one. Using Node\'s `stream.pipeline()` (or `pipeline` from `stream/promises`) instead of manual `.on(\'data\')` handling gets correct backpressure and error propagation for free.', companies: [0] },
];

// A2: type-level rubric templates (packages/shared's Rubric/RubricCriterion
// shape — MOM-023), replacing the single generic {strong,weak} object every
// question previously shared regardless of type. One template per question
// "family" — not 385 bespoke rubrics, which would be authoring effort with no
// principled per-question weight differences — but each family's criteria are
// genuinely different, matching how that family is actually assessed:
// - dsa: correctness/complexity/edge-cases/communication (how a coding answer
//   is judged).
// - system_design: the same 7 sections SystemDesignAnswerPanel's fixed
//   template already asks the user to fill in (Requirements/Estimation/API/
//   Data model/High-level design/Deep dives/Tradeoffs), so the rubric
//   literally scores what the answer form structures.
// - behavioral: STAR completeness/specificity/ownership/reflection.
// - everything else (backend, js/ts/nodejs, db, os, networking, oop, cpp,
//   concurrency, computer_architecture, machine_learning, hpc, quant): a
//   conceptual-accuracy/depth/tradeoffs template — these are all "explain a
//   CS concept" questions at heart, differing in topic, not in how a good
//   answer is judged.
// All criteria weights sum to 100 (maxScore) so scoring is a plain percentage.
const RUBRIC_TEMPLATES: Record<'dsa' | 'system_design' | 'behavioral' | 'cs_fundamentals', RubricCriterion[]> = {
  dsa: [
    { id: 'correctness', title: 'Correctness', description: 'Produces a correct solution that satisfies the stated constraints.', weight: 45 },
    { id: 'complexity', title: 'Complexity analysis', description: 'States and justifies the time and space complexity of the approach.', weight: 20 },
    { id: 'edge_cases', title: 'Edge cases', description: 'Explicitly identifies and handles edge cases (empty input, duplicates, boundaries, overflow).', weight: 15 },
    { id: 'communication', title: 'Communication', description: 'Explains the approach clearly, including why simpler/alternative approaches were rejected.', weight: 20 },
  ],
  system_design: [
    { id: 'requirements', title: 'Requirements', description: 'Clarifies functional and non-functional requirements before designing.', weight: 10 },
    { id: 'estimation', title: 'Estimation', description: 'Sizes the problem (traffic, storage, throughput) with reasonable back-of-envelope numbers.', weight: 10 },
    { id: 'api', title: 'API design', description: 'Defines a clear, minimal API surface matching the requirements.', weight: 15 },
    { id: 'data_model', title: 'Data model', description: 'Chooses a data model/storage approach that fits the access patterns and scale.', weight: 15 },
    { id: 'high_level_design', title: 'High-level design', description: 'Describes a coherent architecture connecting the major components end to end.', weight: 20 },
    { id: 'deep_dives', title: 'Deep dives', description: 'Goes deep on at least one hard sub-problem (a bottleneck, failure mode, or tricky invariant).', weight: 20 },
    { id: 'tradeoffs', title: 'Tradeoffs', description: 'Names real tradeoffs made and what was given up for them, not just what was chosen.', weight: 10 },
  ],
  behavioral: [
    { id: 'star_completeness', title: 'STAR completeness', description: 'Covers Situation, Task, Action, and Result concretely — not just a summary.', weight: 30 },
    { id: 'specificity', title: 'Specificity', description: 'Uses specific details (numbers, tools, decisions) rather than generic claims.', weight: 25 },
    { id: 'ownership_impact', title: 'Ownership & impact', description: 'Clearly attributes the actions and their outcome to the candidate specifically, with a measurable or concrete result.', weight: 25 },
    { id: 'reflection', title: 'Reflection', description: 'Shows what was learned or what would be done differently.', weight: 20 },
  ],
  cs_fundamentals: [
    { id: 'conceptual_accuracy', title: 'Conceptual accuracy', description: 'States the core concept correctly with no factual errors.', weight: 40 },
    { id: 'depth', title: 'Depth', description: 'Goes beyond a surface-level definition into mechanism or implementation detail.', weight: 30 },
    { id: 'tradeoffs', title: 'Tradeoffs', description: 'Discusses tradeoffs, alternatives, or the boundaries of when the concept applies.', weight: 30 },
  ],
};

function rubricTemplateKey(type: string): keyof typeof RUBRIC_TEMPLATES {
  if (type === 'dsa') return 'dsa';
  if (type === 'system_design') return 'system_design';
  if (type === 'behavioral') return 'behavioral';
  return 'cs_fundamentals';
}

function inferRubric(question: SeedQuestion, questionId: string): Rubric {
  return {
    id: `${questionId}-rubric`,
    objectId: questionId,
    criteria: RUBRIC_TEMPLATES[rubricTemplateKey(question.type)],
    maxScore: 100,
  };
}

export function inferQuestionMetadata(question: SeedQuestion, questionId: string) {
  const roleTags = question.roleTags ?? inferRoleTags(question.type);
  const areaTags = question.areaTags ?? inferAreaTags(question.type);
  const patternTags = question.patternTags ?? inferPatternTags(question);
  const estimatedMinutes = question.difficulty === 'easy' ? 10 : question.difficulty === 'medium' ? 25 : 45;
  const importance = question.difficulty === 'hard' ? 3 : question.difficulty === 'medium' ? 2 : 1;
  return {
    roleTags,
    areaTags,
    patternTags,
    estimatedMinutes,
    importance,
    rubric: inferRubric(question, questionId),
  };
}

function inferRoleTags(type: string): string[] {
  if (type === 'hpc' || type === 'cpp' || type === 'concurrency' || type === 'computer_architecture') return ['hpc-gpu-engineer'];
  if (type === 'quant') return ['quant-swe'];
  if (type === 'dsa') return ['big-tech-swe', 'google-l4-swe', 'quant-swe', 'hpc-gpu-engineer'];
  if (type === 'system_design' || type === 'backend') return ['big-tech-swe', 'google-l4-swe', 'quant-swe'];
  return ['big-tech-swe', 'google-l4-swe'];
}

function inferAreaTags(type: string): string[] {
  if (type === 'dsa') return ['dsa'];
  if (type === 'system_design' || type === 'backend') return ['system_design'];
  if (type === 'oop') return ['lld_oop'];
  if (['database', 'os', 'networking', 'concurrency', 'computer_architecture'].includes(type)) return ['cs_fundamentals'];
  if (['javascript', 'typescript', 'nodejs', 'cpp'].includes(type)) return ['language_runtime'];
  if (type === 'hpc' || type === 'quant' || type === 'machine_learning') return ['domain_knowledge'];
  if (type === 'behavioral') return ['behavioral'];
  return ['cs_fundamentals'];
}

function inferPatternTags(question: SeedQuestion): string[] {
  const text = `${question.title} ${question.prompt}`.toLowerCase();
  const tags = ['cache', 'queue', 'transaction', 'index', 'thread', 'memory', 'tcp', 'http', 'design', 'latency', 'probability', 'cuda', 'mpi', 'oop', 'dp', 'graph']
    .filter((tag) => text.includes(tag));
  return tags.length ? tags : [question.type];
}

